                            </div>
                            {selectedMicro && allowedDocTypes.length === 0 && (
                                <p className="text-xs text-red-400 mt-2 flex items-center gap-1">
                                    <AlertTriangle size={12} /> Este microproceso no tiene documentos configurados en la matriz.
                                </p>
