}

const AdminAssignments: React.FC<Props> = ({ user }) => {
  const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [seeding, setSeeding] = useState(false);

  // State for deletion
  const [hiddenIds, setHiddenIds] = useState<Set<string>>(new Set());
  const [deletingIds, setDeletingIds] = useState<Set<string>>(new Set());

  // Filters State
  const [filterProject, setFilterProject] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterMicro, setFilterMicro] = useState(''); 
  const [filterAnalyst, setFilterAnalyst] = useState('');

  const [expandedProjects, setExpandedProjects] = useState<Record<string, boolean>>({ 'HPC': true, 'HSR': true });

  // Edit Assignment Modal State
  const [showEditModal, setShowEditModal] = useState(false);
  const [modalProject, setModalProject] = useState('');
  const [modalMacro, setModalMacro] = useState('');
  const [modalProcess, setModalProcess] = useState('');
  const [modalMicro, setModalMicro] = useState('');
  const [currentAssignees, setCurrentAssignees] = useState<string[]>([]);
  const [originalAssignees, setOriginalAssignees] = useState<string[]>([]);
  const [matrixKeyToUpdate, setMatrixKeyToUpdate] = useState<string | null>(null);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async (showLoader = true) => {
    if (showLoader) setLoading(true);
    try {
        const [h, u] = await Promise.all([
          HierarchyService.getFullHierarchy(),
          UserService.getAll()
        ]);
        setHierarchy(h);
        setAllUsers(u);
    } catch (e) {
        console.error("Error loading assignments data:", e);
    } finally {
        if (showLoader) setLoading(false);
    }
  };

  const handleSeedDefaults = async () => {
      if (!window.confirm("¿Restaurar configuración de procesos por defecto?\nEsto agregará los microprocesos base si la base de datos está vacía.")) return;
      setSeeding(true);
      try {
          await HierarchyService.seedDefaults();
          await loadData();
          alert("Datos restaurados correctamente.");
      } catch (e: any) {
          alert("Error: " + e.message);
      } finally {
          setSeeding(false);
      }
  };

  const toggleProject = (proj: string) => {
    setExpandedProjects(prev => ({ ...prev, [proj]: !prev[proj] }));
  };

  // --- DELETE HANDLER (Matching Production Message) ---
  const handleDelete = async (project: string, macro: string, process: string, id: string, microName: string, e: React.MouseEvent) => {
      e.preventDefault();
      e.stopPropagation();

      const cleanId = id?.trim();
      if (!cleanId) return;

      // MENSAJE EXACTO DE LA CAPTURA DE PANTALLA
      const confirmMsg = `¿Estás seguro de que deseas eliminar el microproceso "${microName}" de la matriz?\nEsta acción es irreversible en esta vista.`;

      if(!window.confirm(confirmMsg)) return;

      // 1. Ocultar inmediatamente (Visual)
      setHiddenIds(prev => new Set(prev).add(cleanId));
      setDeletingIds(prev => new Set(prev).add(cleanId)); 

      // 2. ELIMINAR DEL ESTADO LOCAL
      setHierarchy(prev => {
          const next = { ...prev };
          if (next[project] && next[project][macro] && next[project][macro][process]) {
              next[project][macro][process] = next[project][macro][process].filter(node => node.docId !== cleanId);
          }
          return next;
      });

      try {
          await HierarchyService.deleteMicroprocess(cleanId);
      } catch (e: any) {
          console.error("Error API:", e);
          alert("Error en el servidor, pero se ha ocultado localmente: " + e.message);
      } finally {
          setDeletingIds(prev => {
              const next = new Set(prev);
              next.delete(cleanId);
              return next;
          });
      }
  };

  // --- Handlers for EDIT Modal ---
  const handleEditAssignment = (
      proj: string, macro: string, proc: string, microObj: ProcessNode
  ) => {
      setModalProject(proj);
      setModalMacro(macro);
      setModalProcess(proc);
      setModalMicro(microObj.name);
      setMatrixKeyToUpdate(microObj.docId);
      const existing = [...(microObj.assignees || [])];
      setCurrentAssignees(existing);
      setOriginalAssignees(existing);
      setShowEditModal(true);
  };

  const handleAddAssignee = (userId: string) => {
      if (!userId) return;
      if (!currentAssignees.includes(userId)) {
          setCurrentAssignees([...currentAssignees, userId]);
      }
  };

  const handleRemoveAssignee = (userId: string) => {
      setCurrentAssignees(currentAssignees.filter(id => id !== userId));
  };

  const handleSubmitAssignment = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!matrixKeyToUpdate) return;

      try {
          await HierarchyService.updateMatrixAssignment(matrixKeyToUpdate, currentAssignees);

          const addedAssignees = currentAssignees.filter(id => !originalAssignees.includes(id));
          if (addedAssignees.length > 0) {
              await Promise.all(addedAssignees.map(async (targetId) => {
                  await NotificationService.create(
                      targetId,
                      matrixKeyToUpdate!,
                      'ASSIGNMENT',
                      'Nueva Asignación de Proceso',
                      `Se le ha asignado el proceso: ${modalMicro} (${modalProject})`,
                      user.name
                  );
              }));
          }

          setShowEditModal(false);
          await loadData(false); 
      } catch (err: any) {
          alert(err.message);
      }
  };

  const handleToggleRequiredType = async (matrixKey: string, type: DocType) => {
      await HierarchyService.toggleRequiredType(matrixKey, type);
      await loadData(false);
  };

  // --- Filters Helpers ---
  const getAvailableMacros = () => {
      const macros = new Set<string>();
      Object.keys(hierarchy).forEach(proj => {
          if (filterProject && proj !== filterProject) return;
          Object.keys(hierarchy[proj]).forEach(m => macros.add(m));
      });
      return Array.from(macros).sort();
  };

  const getAvailableProcesses = () => {
      const processes = new Set<string>();
      Object.keys(hierarchy).forEach(proj => {
          if (filterProject && proj !== filterProject) return;
          Object.keys(hierarchy[proj]).forEach(m => {
              if (filterMacro && m !== filterMacro) return;
              Object.keys(hierarchy[proj][m]).forEach(p => processes.add(p));
          });
      });
      return Array.from(processes).sort();
  };

  const clearFilters = () => {
      setFilterProject('');
      setFilterMacro('');
      setFilterProcess('');
      setFilterMicro('');
      setFilterAnalyst('');
  };

  // Flattened Data for Table View within Project
  const getFlattenedRows = (project: string) => {
      const rows: any[] = [];
      const macros = hierarchy[project] || {};

      Object.keys(macros).forEach(macro => {
          if (filterMacro && macro !== filterMacro) return;

          Object.keys(macros[macro]).forEach(proc => {
              if (filterProcess && proc !== filterProcess) return;

              const nodes = macros[macro][proc];
              nodes.forEach(node => {
                  if (hiddenIds.has(node.docId)) return; // Skip deleted locally

                  // IMPORTANT: Filter out inactive nodes (Soft Deleted in Hierarchy)
                  // This ensures consistency between views.
                  if (node.active === false) return; 

                  if (filterMicro && !node.name.toLowerCase().includes(filterMicro.toLowerCase())) return;
                  if (filterAnalyst && (!node.assignees || !node.assignees.includes(filterAnalyst))) return;
                  rows.push({ macro, proc, node });
              });
          });
      });
      return rows;
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando matriz de procesos...</div>;

  const hasActiveFilters = filterProject || filterMacro || filterProcess || filterMicro || filterAnalyst;
  const isHierarchyEmpty = Object.keys(hierarchy).length === 0;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Gestor de Asignaciones</h1>
          <p className="text-slate-500">Asigne analistas responsables y defina documentos requeridos.</p>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
             {isHierarchyEmpty && (
                 <button 
                    onClick={handleSeedDefaults}
                    disabled={seeding}
                    className="flex items-center px-4 py-2 bg-yellow-50 text-yellow-700 border border-yellow-200 rounded-lg hover:bg-yellow-100 transition-colors shadow-sm font-medium whitespace-nowrap"
                >
                    <RefreshCw size={18} className={`mr-2 ${seeding ? 'animate-spin' : ''}`} />
                    {seeding ? 'Restaurando...' : 'Cargar Datos por Defecto'}
                </button>
             )}
        </div>
      </div>

      {/* FILTER BAR */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4">
          <div className="flex items-center justify-between mb-3 border-b border-slate-100 pb-2">
              <h3 className="font-semibold text-slate-700 flex items-center gap-2">
                  <Filter size={18} className="text-indigo-600" /> Filtros de Matriz
              </h3>
              {hasActiveFilters && (
                  <button onClick={clearFilters} className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1">
                      <X size={14} /> Limpiar Todo
                  </button>
              )}
          </div>
          <div className="grid grid-cols-1 md:grid-cols-5 gap-3">
              <select 
                  value={filterProject} 
                  onChange={(e) => setFilterProject(e.target.value)}
                  className="p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                  <option value="">Proyecto (Todos)</option>
                  {Object.keys(hierarchy).map(p => <option key={p} value={p}>{p}</option>)}
              </select>

              <select 
                  value={filterMacro} 
                  onChange={(e) => setFilterMacro(e.target.value)}
                  className="p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                  <option value="">Macroproceso (Todos)</option>
                  {getAvailableMacros().map(m => <option key={m} value={m}>{m}</option>)}
              </select>

              <select 
                  value={filterProcess} 
                  onChange={(e) => setFilterProcess(e.target.value)}
                  className="p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                  <option value="">Proceso (Todos)</option>
                  {getAvailableProcesses().map(p => <option key={p} value={p}>{p}</option>)}
              </select>

              <div className="relative">
                  <Search size={16} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" />
                  <input 
                      type="text" 
                      placeholder="Buscar Microproceso..."
                      value={filterMicro}
                      onChange={(e) => setFilterMicro(e.target.value)}
                      className="w-full pl-8 p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
              </div>

               <select 
                  value={filterAnalyst} 
                  onChange={(e) => setFilterAnalyst(e.target.value)}
                  className="p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                  <option value="">Analista (Todos)</option>
                  {allUsers
                    .filter(u => u.role === UserRole.ANALYST) // Strict Filter
                    .map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
              </select>
          </div>
      </div>

      {isHierarchyEmpty && (
          <div className="p-8 bg-slate-50 border border-slate-200 rounded-xl text-center">
              <Layers size={48} className="mx-auto text-slate-300 mb-3" />
              <h3 className="text-lg font-bold text-slate-700">La Matriz de Procesos está vacía</h3>
              <p className="text-slate-500 mb-4">No se han definido procesos ni asignaciones aún.</p>
              <button 
                onClick={handleSeedDefaults}
                disabled={seeding}
                className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-sm font-medium"
              >
                  Cargar Datos por Defecto
              </button>
          </div>
      )}

      <div className="space-y-4">
        {Object.keys(hierarchy).map(projectKey => {
            if (filterProject && projectKey !== filterProject) return null;

            const rows = getFlattenedRows(projectKey);
            if (rows.length === 0) return null;

            return (
                <div key={projectKey} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                    {/* Project Header */}
                    <div 
                        onClick={() => toggleProject(projectKey)}
                        className="flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 cursor-pointer transition-colors border-b border-slate-200"
                    >
                        <div className="flex items-center gap-2 font-bold text-slate-800 text-lg">
                            {expandedProjects[projectKey] ? <ChevronDown size={20} /> : <ChevronRight size={20} />}
                            <FolderTree size={20} className="text-indigo-600" />
                            Proyecto {projectKey}
                        </div>
                        <span className="text-xs text-slate-500 font-medium bg-white px-2 py-1 rounded border border-slate-200">
                            {rows.length} Microprocesos
                        </span>
                    </div>

                    {/* Table View */}
                    {expandedProjects[projectKey] && (
                        <div className="overflow-x-auto">
                            <table className="w-full text-sm text-left">
                                <thead className="text-xs text-slate-500 uppercase bg-slate-50/50">
                                    <tr>
                                        <th className="px-4 py-3 w-1/4">Jerarquía (Macro / Proceso)</th>
                                        <th className="px-4 py-3 w-1/4">Microproceso</th>
                                        <th className="px-4 py-3 w-1/5">Documentos Definidos</th>
                                        <th className="px-4 py-3 w-1/4">Analistas Responsables</th>
                                        <th className="px-4 py-3 text-right">Acciones</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {rows.map((row, idx) => (
                                        <tr key={`${row.node.docId}-${idx}`} className="hover:bg-slate-50 transition-colors">
                                            {/* Jerarquía */}
                                            <td className="px-4 py-3 align-top text-slate-600">
                                                <div className="font-semibold text-xs text-slate-700 mb-0.5">{row.macro}</div>
                                                <div className="text-xs text-slate-500 pl-2 border-l-2 border-slate-200">{row.proc}</div>
                                            </td>

                                            {/* Microproceso */}
                                            <td className="px-4 py-3 align-top">
                                                <span className="font-medium text-slate-900">{row.node.name}</span>
                                            </td>

                                            {/* Documentos Checkboxes */}
                                            <td className="px-4 py-3 align-top">
                                                <div className="flex items-center gap-2 flex-wrap">
                                                    {['AS IS', 'FCE', 'PM', 'TO BE'].map((type) => {
                                                        const isChecked = row.node.requiredTypes && row.node.requiredTypes.includes(type as DocType);
                                                        return (
                                                            <button 
                                                                key={type}
                                                                onClick={() => handleToggleRequiredType(row.node.docId, type as DocType)}
                                                                className={`flex items-center gap-1 px-1.5 py-0.5 rounded text-[10px] font-bold border transition-all ${
                                                                    isChecked 
                                                                    ? 'bg-indigo-100 text-indigo-700 border-indigo-200 hover:bg-indigo-200' 
                                                                    : 'bg-slate-50 text-slate-300 border-slate-200 hover:border-slate-300'
                                                                }`}
                                                                title={`Alternar ${type}`}
                                                            >
                                                                {isChecked ? <CheckSquare size={10} /> : <Square size={10} />}
                                                                {type}
                                                            </button>
                                                        );
                                                    })}
                                                </div>
                                            </td>

                                            {/* Analistas */}
                                            <td className="px-4 py-3 align-top">
                                                {(row.node.assignees && row.node.assignees.length > 0) ? (
                                                    <>
                                                        <div className="flex -space-x-2 overflow-hidden py-1">
                                                            {row.node.assignees.map((aid: string) => {
                                                                const u = allUsers.find(user => user.id === aid);
                                                                if (!u) {
                                                                    return (
                                                                         <div key={aid} className="inline-flex h-6 w-6 items-center justify-center rounded-full ring-2 ring-white bg-slate-200 text-[10px] text-slate-500 font-bold cursor-help" title={`Usuario ID: ${aid} no encontrado`}>?</div>
                                                                    );
                                                                }
                                                                return (
                                                                    <div key={u.id} className="inline-block h-6 w-6 rounded-full ring-2 ring-white bg-indigo-100 overflow-hidden" title={u.name}>
                                                                        {u.avatar ? <img src={u.avatar} className="h-full w-full object-cover" /> : <span className="flex h-full w-full items-center justify-center text-[10px] font-bold text-indigo-700">{u.name.charAt(0)}</span>}
                                                                    </div>
                                                                );
                                                            })}
                                                        </div>
                                                        <div className="text-xs text-slate-500 mt-1 truncate">
                                                             {row.node.assignees.map((aid: string) => {
                                                                 const u = allUsers.find(user => user.id === aid);
                                                                 return u ? u.name : 'Desconocido';
                                                             }).join(', ')}
                                                        </div>
                                                    </>
                                                ) : (
                                                    <span className="text-xs text-red-400 italic py-1 block">Sin asignar</span>
                                                )}
                                            </td>

                                            {/* Acciones */}
                                            <td className="px-4 py-3 align-top text-right">
                                                <div className="flex justify-end gap-1">
                                                    <button 
                                                        onClick={() => handleEditAssignment(projectKey, row.macro, row.proc, row.node)}
                                                        className="text-slate-400 hover:text-indigo-600 p-1.5 hover:bg-indigo-50 rounded transition-colors"
                                                        title="Editar Asignación"
                                                    >
                                                        <Users size={16} />
                                                    </button>
                                                    {/* Botón de Eliminar Restaurado */}
                                                    <button 
                                                        onClick={(e) => handleDelete(projectKey, row.macro, row.proc, row.node.docId, row.node.name, e)}
                                                        className="text-slate-400 hover:text-red-600 p-1.5 hover:bg-red-50 rounded transition-colors"
                                                        title="Eliminar Microproceso"
                                                        disabled={deletingIds.has(row.node.docId?.trim())}
                                                    >
                                                        {deletingIds.has(row.node.docId?.trim()) ? (
                                                            <Loader2 size={16} className="animate-spin text-red-600" />
                                                        ) : (
                                                            <Trash2 size={16} />
                                                        )}
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    ))}
                                    {rows.length === 0 && (
                                        <tr><td colSpan={5} className="p-4 text-center text-slate-400 text-sm">No se encontraron resultados en este proyecto.</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>
            );
        })}
      </div>

      {/* MODAL 1: EDIT ASSIGNMENT */}
      {showEditModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
            <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden">
                <div className="p-5 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
                    <h3 className="text-lg font-bold text-slate-800">Editar Asignación</h3>
                    <button onClick={() => setShowEditModal(false)} className="text-slate-400 hover:text-slate-600"><X size={20} /></button>
                </div>

                <form onSubmit={handleSubmitAssignment} className="p-6">
                    <div className="mb-6 bg-indigo-50/50 p-4 rounded-lg border border-indigo-100 text-sm">
                        <div className="grid grid-cols-3 gap-y-2">
                             <span className="text-slate-500">Proyecto:</span> <span className="col-span-2 font-medium">{modalProject}</span>
                             <span className="text-slate-500">Proceso:</span> <span className="col-span-2 font-medium">{modalProcess}</span>
                             <span className="text-slate-500 font-bold">Microproceso:</span> <span className="col-span-2 font-bold text-indigo-700">{modalMicro}</span>
                        </div>
                    </div>

                    <div className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">Analistas Asignados</label>
                            <div className="space-y-2 max-h-40 overflow-y-auto border border-slate-200 rounded-lg p-2">
                                {currentAssignees.length === 0 ? (
                                    <p className="text-sm text-slate-400 italic text-center py-2">No hay analistas asignados.</p>
                                ) : (
                                    currentAssignees.map(aid => {
                                        const u = allUsers.find(user => user.id === aid);
                                        return (
                                            <div key={aid} className="flex items-center justify-between p-2 bg-slate-50 rounded border border-slate-100">
                                                <div className="flex items-center gap-2">
                                                    {u && (u.avatar ? <img src={u.avatar} className="w-6 h-6 rounded-full" /> : <div className="w-6 h-6 rounded-full bg-indigo-100 flex items-center justify-center text-xs text-indigo-700 font-bold">{u.name.charAt(0)}</div>)}
                                                    <span className="text-sm font-medium text-slate-700">{u ? u.name : `Usuario Eliminado (${aid})`}</span>
                                                </div>
                                                <button type="button" onClick={() => handleRemoveAssignee(aid)} className="text-red-400 hover:text-red-600">
                                                    <X size={16} />
                                                </button>
                                            </div>
                                        );
                                    })
                                )}
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Agregar Analista</label>
                            <select 
                                className="w-full p-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                                onChange={(e) => handleAddAssignee(e.target.value)}
                                value=""
                            >
                                <option value="">Seleccionar analista para agregar...</option>
                                {allUsers
                                    .filter(u => u.role === UserRole.ANALYST && !currentAssignees.includes(u.id)) // Strict Filter + Exclusion
                                    .map(u => (
                                        <option key={u.id} value={u.id}>{u.name}</option>
                                ))}
                            </select>
                        </div>
                    </div>

                    <div className="flex justify-end pt-6 gap-3">
                        <button 
                            type="button" 
                            onClick={() => setShowEditModal(false)}
                            className="px-4 py-2 text-slate-600 hover:text-slate-800 text-sm font-medium"
                        >
                            Cancelar
                        </button>
                        <button 
                            type="submit"
                            className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-medium shadow-sm"
                        >
                            Guardar Cambios
                        </button>
                    </div>
                </form>
            </div>
          </div>
      )}
    </div>
  );
};

export default AdminAssignments;

import React, { useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { DatabaseService } from '../services/firebaseBackend';
import { Download, Upload, Database, AlertTriangle, Save, FileSpreadsheet, RefreshCw, CheckSquare, Clock } from 'lucide-react';

const AdminDatabase: React.FC = () => {
  const navigate = useNavigate();
  const [isExporting, setIsExporting] = useState(false);
  const [isImporting, setIsImporting] = useState(false);

  // RESET & INIT STATE
  const [isResetting, setIsResetting] = useState(false);
  const [resetProgress, setResetProgress] = useState(0);
  const [resetStatus, setResetStatus] = useState<string>('Esperando inicio...');
  const [userConfirmed, setUserConfirmed] = useState(false); 

  const [rulesFile, setRulesFile] = useState<File | null>(null);
  const [historyFile, setHistoryFile] = useState<File | null>(null);

  const rulesInputRef = useRef<HTMLInputElement>(null);
  const historyInputRef = useRef<HTMLInputElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleExport = async () => {
    setIsExporting(true);
    try {
      const jsonString = await DatabaseService.exportData();
      const blob = new Blob([jsonString], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      const date = new Date().toISOString().split('T')[0];
      a.download = `sgd_backup_${date}.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    } catch (error) {
      console.error(error);
      alert('Error al generar el respaldo.');
    } finally {
      setIsExporting(false);
    }
  };

  const handleJsonRestore = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || !e.target.files[0]) return;
    const file = e.target.files[0];

    if (!window.confirm(`¿Restaurar desde "${file.name}"? Se perderán los datos actuales.`)) {
        if (fileInputRef.current) fileInputRef.current.value = '';
        return;
    }

    setIsImporting(true);
    const reader = new FileReader();
    reader.onload = async (event) => {
      try {
        const content = event.target?.result as string;
        await DatabaseService.importData(content);
        alert('Base de datos restaurada exitosamente.');
        navigate('/'); 
      } catch (error: any) {
        alert('Error al restaurar: ' + error.message);
        if (fileInputRef.current) fileInputRef.current.value = '';
        setIsImporting(false);
      }
    };
    reader.readAsText(file);
  };

  const handleExecuteReset = async () => {
      if (!rulesFile) {
          alert("El archivo de Reglas/Estructura es obligatorio.");
          return;
      }
      // History file is optional but recommended

      if (!userConfirmed) {
          alert("Debe confirmar que entiende que se eliminarán los datos.");
          return;
      }

      setIsResetting(true);
      setResetProgress(1); 
      setResetStatus('Leyendo archivos locales...');

      setTimeout(async () => {
          try {
              // Read Rules
              const rulesContent = await readFileContent(rulesFile, 'ISO-8859-1');

              // Read History if available
              let historyContent = '';
              if (historyFile) {
                  historyContent = await readFileContent(historyFile, 'ISO-8859-1');
              }

              setResetStatus('Conectando con base de datos...');
              console.log("Iniciando carga híbrida...");

              const result = await DatabaseService.fullSystemResetAndImport(
                  rulesContent,
                  historyContent,
                  (percent, status) => {
                      console.log(`Progreso: ${percent}% - ${status}`);
                      setResetProgress(percent);
                      if (status) setResetStatus(status);
                  }
              );

              setResetStatus('¡Éxito! Redirigiendo...');
              setResetProgress(100);

              setTimeout(() => {
                  alert(`CARGA EXITOSA.\n\nMicroprocesos: ${result.created}\nDocumentos Históricos Vinculados: ${result.historyMatched}`);
                  navigate('/'); 
              }, 500);

          } catch (error: any) {
              console.error(error);
              setResetStatus('Error Crítico: ' + error.message);
              setIsResetting(false); 
              alert("Error durante la carga: " + error.message);
          }
      }, 200);
  };

  const readFileContent = (file: File, encoding: string = 'UTF-8'): Promise<string> => {
      return new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = (e) => resolve(e.target?.result as string);
          reader.onerror = (e) => reject(e);
          reader.readAsText(file, encoding);
      });
  };

  return (
    <div className="space-y-6 max-w-4xl mx-auto pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
            <Database className="text-indigo-600" />
            Base de Datos
          </h1>
          <p className="text-slate-500">Gestión de respaldos, recuperación y migración de datos.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

        {/* Card 1: Backup */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <div className="w-12 h-12 bg-green-100 rounded-full flex items-center justify-center mb-4 text-green-600">
                <Download size={24} />
            </div>
            <h2 className="text-lg font-bold text-slate-800 mb-2">Generar Respaldo</h2>
            <p className="text-sm text-slate-500 mb-6">
                Descarga una copia completa de la base de datos actual (JSON).
            </p>
            <button 
                onClick={handleExport}
                disabled={isExporting}
                className="w-full flex items-center justify-center px-4 py-3 bg-green-600 hover:bg-green-700 text-white rounded-lg transition-colors font-medium shadow-sm disabled:opacity-70"
            >
                {isExporting ? 'Generando...' : (
                    <>
                        <Save size={18} className="mr-2" />
                        Descargar JSON
                    </>
                )}
            </button>
        </div>

        {/* Card 2: Restore JSON */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <div className="w-12 h-12 bg-orange-100 rounded-full flex items-center justify-center mb-4 text-orange-600">
                <Upload size={24} />
            </div>
            <h2 className="text-lg font-bold text-slate-800 mb-2">Restaurar Sistema (JSON)</h2>
            <p className="text-sm text-slate-500 mb-6">
                Sube un archivo de respaldo (.json) para restaurar el sistema. 
            </p>

            <input 
                type="file" 
                ref={fileInputRef}
                accept=".json"
                onChange={handleJsonRestore}
                className="hidden"
            />

            <button 
                onClick={() => fileInputRef.current?.click()}
                disabled={isImporting}
                className="w-full flex items-center justify-center px-4 py-3 bg-slate-800 hover:bg-slate-900 text-white rounded-lg transition-colors font-medium shadow-sm disabled:opacity-70"
            >
                {isImporting ? 'Restaurando...' : (
                    <>
                        <Upload size={18} className="mr-2" />
                        Subir Respaldo
                    </>
                )}
            </button>
        </div>

        {/* MAIN CARD: FULL SYSTEM RESET */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-red-200 md:col-span-2 relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-1 bg-red-500"></div>
            <div className="flex flex-col md:flex-row gap-8">
                <div className="flex-1">
                    <div className="flex items-center gap-3 mb-4">
                        <div className="w-12 h-12 bg-red-100 rounded-full flex items-center justify-center text-red-600">
                            <RefreshCw size={24} />
                        </div>
                        <div>
                            <h2 className="text-xl font-bold text-slate-900">Carga Híbrida (Reglas + Histórico)</h2>
                            <p className="text-sm text-red-600 font-semibold flex items-center gap-1">
                                <AlertTriangle size={14} /> Reset Total + Estructura + Estado Actual
                            </p>
                        </div>
                    </div>

                    <p className="text-sm text-slate-600 mb-6">
                        Este proceso <b>borra todo</b> y reconstruye el sistema usando dos fuentes:
                        <ul className="list-disc pl-5 mt-2 space-y-1">
                            <li><b>Reglas:</b> Define la estructura del árbol y los documentos obligatorios.</li>
                            <li><b>Histórico:</b> Define la versión, fecha y estado actual de cada documento.</li>
                        </ul>
                    </p>

                    <div className="space-y-4">
                        {/* File 1: Rules */}
                        <div className="bg-slate-50 p-4 rounded-lg border border-slate-200 hover:border-indigo-300 transition-colors">
                            <div className="flex justify-between items-center mb-2">
                                <span className="text-sm font-bold text-slate-700 flex items-center gap-2"><FileSpreadsheet size={16}/> 1. CSV Reglas (Estructura)</span>
                                {rulesFile ? <span className="text-xs font-bold text-green-600 bg-green-100 px-2 py-0.5 rounded">Cargado</span> : <span className="text-xs text-red-400 font-medium">Requerido</span>}
                            </div>
                            <div className="text-xs text-slate-500 mb-3">
                                <p>Macro; Proceso; Micro; Analista; Proyecto;</p>
                                <p>ASIS; FCE; PM; TOBE (Flags 0/1)</p>
                            </div>
                            <div className="flex gap-3 items-center">
                                <input 
                                    type="file" 
                                    ref={rulesInputRef}
                                    accept=".csv,.txt"
                                    onChange={(e) => setRulesFile(e.target.files?.[0] || null)}
                                    className="hidden"
                                />
                                <button 
                                    onClick={() => rulesInputRef.current?.click()}
                                    className="px-3 py-1.5 bg-white border border-slate-300 text-slate-600 text-xs rounded hover:bg-slate-50 font-medium"
                                >
                                    Seleccionar Archivo
                                </button>
                                <span className="text-xs text-slate-500 truncate max-w-[200px]">{rulesFile?.name || '...'}</span>
                            </div>
                        </div>

                        {/* File 2: History */}
                        <div className="bg-slate-50 p-4 rounded-lg border border-slate-200 hover:border-indigo-300 transition-colors">
                            <div className="flex justify-between items-center mb-2">
                                <span className="text-sm font-bold text-slate-700 flex items-center gap-2"><Clock size={16}/> 2. CSV Histórico (Estado)</span>
                                {historyFile ? <span className="text-xs font-bold text-green-600 bg-green-100 px-2 py-0.5 rounded">Cargado</span> : <span className="text-xs text-slate-400 font-medium">Opcional</span>}
                            </div>
                            <div className="text-xs text-slate-500 mb-3">
                                <p>Proyecto; Macro; Proceso; Micro;</p>
                                <p>Ver/Fecha (ASIS); Ver/Fecha (FCE); ...</p>
                            </div>
                            <div className="flex gap-3 items-center">
                                <input 
                                    type="file" 
                                    ref={historyInputRef}
                                    accept=".csv,.txt"
                                    onChange={(e) => setHistoryFile(e.target.files?.[0] || null)}
                                    className="hidden"
                                />
                                <button 
                                    onClick={() => historyInputRef.current?.click()}
                                    className="px-3 py-1.5 bg-white border border-slate-300 text-slate-600 text-xs rounded hover:bg-slate-50 font-medium"
                                >
                                    Seleccionar Archivo
                                </button>
                                <span className="text-xs text-slate-500 truncate max-w-[200px]">{historyFile?.name || '...'}</span>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="flex flex-col justify-center items-center md:w-1/3 gap-4 border-l border-slate-100 md:pl-6">
                     <div className="bg-indigo-50 p-3 rounded text-xs text-indigo-800 w-full mb-2">
                        <p className="font-bold mb-1 border-b border-indigo-100 pb-1">El proceso realizará:</p>
                        <ol className="list-decimal pl-4 space-y-1 mt-1">
                            <li>Eliminar Base de Datos actual.</li>
                            <li>Crear estructura base desde (1).</li>
                            <li>Actualizar estado/fecha desde (2).</li>
                            <li>Si no hay (2), inicia en 0.0.</li>
                        </ol>
                     </div>

                     <label className="flex items-start gap-2 text-xs text-slate-600 cursor-pointer p-2 rounded hover:bg-slate-50 w-full">
                        <div className="relative flex items-center">
                            <input 
                                type="checkbox" 
                                checked={userConfirmed}
                                onChange={(e) => setUserConfirmed(e.target.checked)}
                                disabled={isResetting}
                                className="peer h-4 w-4 cursor-pointer appearance-none rounded border border-slate-300 shadow-sm checked:bg-red-600 checked:border-red-600"
                            />
                            <CheckSquare className="absolute w-4 h-4 text-white opacity-0 peer-checked:opacity-100 pointer-events-none" size={12} />
                        </div>
                        <span>Confirmo <b>eliminar datos</b> y recargar.</span>
                     </label>

                     <button 
                        onClick={handleExecuteReset}
                        disabled={isResetting || !rulesFile || !userConfirmed}
                        className={`w-full flex items-center justify-center px-4 py-3 rounded-lg transition-all font-bold shadow-md text-white text-sm
                            ${(rulesFile && userConfirmed) 
                                ? 'bg-red-600 hover:bg-red-700 hover:shadow-lg transform active:scale-95' 
                                : 'bg-slate-300 cursor-not-allowed opacity-70'}`}
                    >
                        {isResetting ? (
                            <span className="flex items-center animate-pulse">
                                <RefreshCw size={16} className="animate-spin mr-2" /> PROCESANDO...
                            </span>
                        ) : 'EJECUTAR CARGA'}
                    </button>

                    {/* Barra de Progreso */}
                    {isResetting && (
                        <div className="w-full bg-white p-3 rounded-lg border border-red-100 shadow-sm mt-2 transition-all duration-300">
                             <div className="flex justify-between text-xs text-red-700 font-bold mb-2">
                                <span>Progreso</span>
                                <span>{resetProgress}%</span>
                            </div>
                            <div className="w-full bg-slate-100 rounded-full h-3 overflow-hidden border border-slate-200">
                                <div 
                                    className="bg-red-500 h-3 rounded-full transition-all duration-300 ease-out" 
                                    style={{ width: `${resetProgress}%` }}
                                ></div>
                            </div>
                            <p className="text-[10px] text-center text-slate-500 mt-2 font-mono bg-slate-50 p-1 rounded border border-slate-100 truncate">
                                {resetStatus}
                            </p>
                        </div>
                    )}
                </div>
            </div>
        </div>

      </div>
    </div>
  );
};

export default AdminDatabase;

import React, { useState, useEffect, useMemo } from 'react';
import { HierarchyService, generateMatrixId } from '../services/firebaseBackend';
import { FullHierarchy, ProcessNode, User, UserRole } from '../types';
import { 
  FolderTree, ChevronRight, ChevronDown, Plus, X, Edit, Trash2, Save, Layers, Network, FolderOpen, FileText, Loader2, Search, Eye, EyeOff, Power, FolderInput, ArrowRight, AlertTriangle
} from 'lucide-react';

interface Props {
    user: User;
}

const AdminHierarchy: React.FC<Props> = ({ user }) => {
  const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
  const [loading, setLoading] = useState(true);

  // Selection State
  const [selectedProject, setSelectedProject] = useState<string | null>(null);
  const [selectedMacro, setSelectedMacro] = useState<string | null>(null);
  const [selectedProcess, setSelectedProcess] = useState<string | null>(null);

  // Search State
  const [searchTerm, setSearchTerm] = useState('');

  // View Options
  const [showInactive, setShowInactive] = useState(false);

  // Modal State
  const [showAddModal, setShowAddModal] = useState(false);
  const [addLevel, setAddLevel] = useState<'PROJECT' | 'MACRO' | 'PROCESS' | 'MICRO'>('PROJECT');
  const [newItemName, setNewItemName] = useState('');

  // Rename State
  const [renameMode, setRenameMode] = useState<{ level: string, oldName: string } | null>(null);
  const [renameValue, setRenameValue] = useState('');

  // Move Modal State
  const [showMoveModal, setShowMoveModal] = useState(false);
  const [moveTarget, setMoveTarget] = useState<{ docId: string, name: string, currentProject: string, currentMacro: string, currentProcess: string } | null>(null);
  const [targetProject, setTargetProject] = useState('');
  const [targetMacro, setTargetMacro] = useState('');
  const [targetProcess, setTargetProcess] = useState('');

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
        const h = await HierarchyService.getFullHierarchy();
        setHierarchy(h);
    } catch (e) {
        console.error("Error loading hierarchy:", e);
    } finally {
        setLoading(false);
    }
  };

  // --- ACTIONS ---

  const handleAdd = (level: 'PROJECT' | 'MACRO' | 'PROCESS' | 'MICRO') => {
      setAddLevel(level);
      setNewItemName('');
      setShowAddModal(true);
  };

  const handleCreateSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!newItemName.trim()) return;

      try {
          let project = selectedProject || newItemName;
          let macro = selectedMacro || (addLevel === 'PROJECT' ? 'General' : newItemName);
          let process = selectedProcess || ((addLevel === 'PROJECT' || addLevel === 'MACRO') ? 'General' : newItemName);
          let micro = (addLevel === 'MICRO') ? newItemName : 'Inicio';

          if (addLevel === 'PROJECT') project = newItemName;
          if (addLevel === 'MACRO') macro = newItemName;
          if (addLevel === 'PROCESS') process = newItemName;

          await HierarchyService.addMicroprocess(project, macro, process, micro, [], ['AS IS', 'FCE', 'PM', 'TO BE']);

          setShowAddModal(false);
          await loadData();

          if (addLevel === 'PROJECT') setSelectedProject(newItemName);
          if (addLevel === 'MACRO') setSelectedMacro(newItemName);
          if (addLevel === 'PROCESS') setSelectedProcess(newItemName);

      } catch (err: any) {
          alert('Error: ' + err.message);
      }
  };

  const handleToggleStatus = async (id: string, name: string, currentStatus: boolean, e: React.MouseEvent) => {
      e.stopPropagation();
      // Soft delete confirmation
      const action = currentStatus ? "Inactivar" : "Reactivar";
      const confirmMsg = currentStatus 
        ? `¿Inactivar microproceso "${name}"?\nDejará de estar disponible para nuevos documentos, pero se conservará el historial.`
        : `¿Reactivar microproceso "${name}"?`;

      if (!window.confirm(confirmMsg)) return;

      try {
          await HierarchyService.toggleProcessStatus(id, currentStatus);
          await loadData(); // Reload to reflect changes
      } catch (e: any) {
          alert(`Error al ${action.toLowerCase()}: ` + e.message);
      }
  };

  // --- HARD DELETE MICROPROCESS (ADMIN ONLY) ---
  const handleHardDeleteMicro = async (id: string, name: string, e: React.MouseEvent) => {
      e.stopPropagation();

      const confirmMsg = `⚠️ PELIGRO: Eliminación Permanente ⚠️\n\n¿Estás seguro de que deseas ELIMINAR definitivamente el microproceso "${name}"?\n\nEsta acción borrará el nodo de la estructura y romperá la relación con los documentos existentes.`;

      if (!window.confirm(confirmMsg)) return;

      // OPTIMISTIC UPDATE: Remove from UI immediately
      setHierarchy(prev => {
          const next = { ...prev };
          // Deep traversal to find and remove the node in local state
          Object.keys(next).forEach(proj => {
              Object.keys(next[proj]).forEach(macro => {
                  Object.keys(next[proj][macro]).forEach(proc => {
                      next[proj][macro][proc] = next[proj][macro][proc].filter(n => n.docId !== id);
                  });
              });
          });
          return next;
      });

      try {
          // No global loading spinner to keep the UI fluid, the item is already gone
          await HierarchyService.deleteMicroprocess(id);
          // Background sync to ensure consistency
          setTimeout(loadData, 500); 
      } catch (e: any) {
          alert("Error al eliminar: " + e.message);
          loadData(); // Revert on error
      }
  };

  // NEW: Delete logic for parent nodes
  const handleDeleteNode = async (level: 'PROJECT' | 'MACRO' | 'PROCESS', name: string, e: React.MouseEvent) => {
      e.stopPropagation();

      // Additional safety check on frontend
      if (user.role !== UserRole.ADMIN) {
          alert("Acción no permitida. Solo administradores.");
          return;
      }

      const warningMsg = `⚠️ ADVERTENCIA CRÍTICA ⚠️\n\nEstá a punto de eliminar el ${level}: "${name}".\n\nEsta acción ELIMINARÁ TODOS los datos contenidos en él (Macroprocesos, Procesos y Microprocesos). \n\n¿Está absolutamente seguro?`;

      if (!window.confirm(warningMsg)) return;

      try {
          setLoading(true);
          const parentContext = {
              project: selectedProject || undefined,
              macro: selectedMacro || undefined
          };

          await HierarchyService.deleteHierarchyNode(level, name, parentContext);

          // Clear selections if deleted
          if (level === 'PROJECT' && selectedProject === name) { setSelectedProject(null); setSelectedMacro(null); setSelectedProcess(null); }
          if (level === 'MACRO' && selectedMacro === name) { setSelectedMacro(null); setSelectedProcess(null); }
          if (level === 'PROCESS' && selectedProcess === name) { setSelectedProcess(null); }

          await loadData();
      } catch (err: any) {
          alert("Error al eliminar: " + err.message);
          setLoading(false);
      }
  };

  const handleRenameStart = (level: 'PROJECT' | 'MACRO' | 'PROCESS', oldName: string) => {
      setRenameMode({ level, oldName });
      setRenameValue(oldName);
  };

  const handleRenameSubmit = async () => {
      if (!renameMode || !renameValue.trim() || renameValue === renameMode.oldName) {
          setRenameMode(null);
          return;
      }

      if (!window.confirm(`¿Renombrar "${renameMode.oldName}" a "${renameValue}"?\nEsto actualizará TODOS los microprocesos contenidos en esta carpeta.`)) return;

      try {
          setLoading(true);
          const parentContext = {
              project: selectedProject || undefined,
              macro: selectedMacro || undefined
          };

          await HierarchyService.updateHierarchyNode(
              renameMode.level as any, 
              renameMode.oldName, 
              renameValue, 
              parentContext
          );

          if (renameMode.level === 'PROJECT' && selectedProject === renameMode.oldName) setSelectedProject(renameValue);
          if (renameMode.level === 'MACRO' && selectedMacro === renameMode.oldName) setSelectedMacro(renameValue);
          if (renameMode.level === 'PROCESS' && selectedProcess === renameMode.oldName) setSelectedProcess(renameValue);

          setRenameMode(null);
          await loadData();
      } catch (e: any) {
          alert('Error al renombrar: ' + e.message);
          setLoading(false);
      }
  };

  // --- MOVE / RELOCATE LOGIC ---
  const handleMoveStart = (micro: ProcessNode, e: React.MouseEvent) => {
      e.stopPropagation();
      setMoveTarget({
          docId: micro.docId,
          name: micro.name,
          currentProject: selectedProject || '',
          currentMacro: selectedMacro || '',
          currentProcess: selectedProcess || ''
      });
      // Pre-fill current values or defaults
      setTargetProject(selectedProject || '');
      setTargetMacro(selectedMacro || '');
      setTargetProcess(selectedProcess || '');
      setShowMoveModal(true);
  };

  const handleMoveSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!moveTarget || !targetProject || !targetMacro || !targetProcess) return;

      // Verification
      if (targetProject === moveTarget.currentProject && targetMacro === moveTarget.currentMacro && targetProcess === moveTarget.currentProcess) {
          alert("El destino es el mismo que el origen. No se realizaron cambios.");
          setShowMoveModal(false);
          return;
      }

      try {
          setLoading(true);
          await HierarchyService.moveMicroprocess(moveTarget.docId, targetProject, targetMacro, targetProcess);
          setShowMoveModal(false);
          await loadData();
      } catch (err: any) {
          alert('Error al reubicar: ' + err.message);
      } finally {
          setLoading(false);
      }
  };

  // --- MEMOIZED FLATTENED LIST FOR SEARCH ---
  const flatNodes = useMemo(() => {
      const list: { 
          project: string, macro: string, process: string, micro: ProcessNode, path: string 
      }[] = [];

      Object.keys(hierarchy).forEach(proj => {
          Object.keys(hierarchy[proj]).forEach(macro => {
              Object.keys(hierarchy[proj][macro]).forEach(proc => {
                  hierarchy[proj][macro][proc].forEach(node => {
                      if (!showInactive && node.active === false) return;
                      list.push({
                          project: proj,
                          macro: macro,
                          process: proc,
                          micro: node,
                          path: `${proj} > ${macro} > ${proc} > ${node.name}`
                      });
                  });
              });
          });
      });
      return list;
  }, [hierarchy, showInactive]);

  const searchResults = useMemo(() => {
      if (!searchTerm) return [];
      const lower = searchTerm.toLowerCase();
      return flatNodes.filter(item => 
          item.path.toLowerCase().includes(lower) || 
          item.micro.name.toLowerCase().includes(lower)
      );
  }, [searchTerm, flatNodes]);


  // --- RENDER HELPERS ---

  if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Cargando estructura...</div>;

  // Data Pointers (Standard Column View)
  const projects = Object.keys(hierarchy).sort();
  const macros = selectedProject && hierarchy[selectedProject] ? Object.keys(hierarchy[selectedProject]).sort() : [];
  const processes = selectedProject && selectedMacro && hierarchy[selectedProject][selectedMacro] ? Object.keys(hierarchy[selectedProject][selectedMacro]).sort() : [];

