                              <ChevronRight size={12}/>
                              <span className="bg-white px-2 py-0.5 rounded border">{moveTarget.currentMacro}</span>
                              <ChevronRight size={12}/>
                              <span className="bg-white px-2 py-0.5 rounded border">{moveTarget.currentProcess}</span>
