                      </div>

                      <div className="space-y-4">
                          <div>
                              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Proyecto Destino</label>
                              <select 
                                  value={targetProject}
                                  onChange={(e) => {
                                      setTargetProject(e.target.value);
                                      setTargetMacro(''); // Reset downstream
                                      setTargetProcess('');
