import React, { useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { DatabaseService } from '../services/firebaseBackend';
import { Download, Upload, Database, AlertTriangle, Save, FileSpreadsheet, RefreshCw, CheckSquare, Clock } from 'lucide-react';

const AdminDatabase: React.FC = () => {
  const navigate = useNavigate();
  const [isExporting, setIsExporting] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const [isResetting, setIsResetting] = useState(false);
  const [resetProgress, setResetProgress] = useState(0);
  const [resetStatus, setResetStatus] = useState<string>('Esperando inicio...');
  const [userConfirmed, setUserConfirmed] = useState(false); 
  const [rulesFile, setRulesFile] = useState<File | null>(null);
  const [historyFile, setHistoryFile] = useState<File | null>(null);
  const rulesInputRef = useRef<HTMLInputElement>(null);
  const historyInputRef = useRef<HTMLInputElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleExport = async () => {
    setIsExporting(true);
    try {
      const jsonString = await DatabaseService.exportData();
      const blob = new Blob([jsonString], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      const date = new Date().toISOString().split('T')[0];
      a.download = `sgd_backup_${date}.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    } catch (error) {
      console.error(error);
      alert('Error al generar el respaldo.');
    } finally {
      setIsExporting(false);
    }
  };

  const handleJsonRestore = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || !e.target.files[0]) return;
    const file = e.target.files[0];
    if (!window.confirm(`¿Restaurar desde "${file.name}"? Se perderán los datos actuales.`)) {
        if (fileInputRef.current) fileInputRef.current.value = '';
        return;
    }
    setIsImporting(true);
    const reader = new FileReader();
    reader.onload = async (event) => {
      try {
        const content = event.target?.result as string;
        await DatabaseService.importData(content);
        alert('Base de datos restaurada exitosamente.');
        navigate('/'); 
      } catch (error: any) {
        alert('Error al restaurar: ' + error.message);
        if (fileInputRef.current) fileInputRef.current.value = '';
        setIsImporting(false);
      }
    };
    reader.readAsText(file);
  };

  const handleExecuteReset = async () => {
      if (!rulesFile) {
          alert("El archivo de Reglas/Estructura es obligatorio.");
          return;
      }
      if (!userConfirmed) {
          alert("Debe confirmar que entiende que se eliminarán los datos.");
          return;
      }
      setIsResetting(true);
      setResetProgress(1); 
      setResetStatus('Leyendo archivos locales...');
      setTimeout(async () => {
          try {
              const rulesContent = await readFileContent(rulesFile, 'ISO-8859-1');
              let historyContent = '';
              if (historyFile) { historyContent = await readFileContent(historyFile, 'ISO-8859-1'); }
              setResetStatus('Conectando con base de datos...');
              const result = await DatabaseService.fullSystemResetAndImport(rulesContent, historyContent, (percent, status) => {
                  setResetProgress(percent);
                  if (status) setResetStatus(status);
              });
              setResetStatus('¡Éxito! Redirigiendo...');
              setResetProgress(100);
              setTimeout(() => {
                  alert(`CARGA EXITOSA.\n\nMicroprocesos: ${result.created}`);
                  navigate('/'); 
              }, 500);
          } catch (error: any) {
              setResetStatus('Error Crítico: ' + error.message);
              setIsResetting(false); 
              alert("Error durante la carga: " + error.message);
          }
      }, 200);
  };

  const readFileContent = (file: File, encoding: string = 'UTF-8'): Promise<string> => {
      return new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = (e) => resolve(e.target?.result as string);
          reader.onerror = (e) => reject(e);
          reader.readAsText(file, encoding);
      });
  };

  return (
    <div className="space-y-6 max-w-4xl mx-auto pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2"><Database className="text-indigo-600" /> Base de Datos</h1>
          <p className="text-slate-500">Gestión de respaldos, recuperación y migración de datos.</p>
        </div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <div className="w-12 h-12 bg-green-100 rounded-full flex items-center justify-center mb-4 text-green-600"><Download size={24} /></div>
            <h2 className="text-lg font-bold text-slate-800 mb-2">Generar Respaldo</h2>
            <p className="text-sm text-slate-500 mb-6">Descarga una copia completa de la base de datos actual (JSON).</p>
            <button onClick={handleExport} disabled={isExporting} className="w-full flex items-center justify-center px-4 py-3 bg-green-600 hover:bg-green-700 text-white rounded-lg transition-colors font-medium shadow-sm disabled:opacity-70">{isExporting ? 'Generando...' : <><Save size={18} className="mr-2" /> Descargar JSON</>}</button>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <div className="w-12 h-12 bg-orange-100 rounded-full flex items-center justify-center mb-4 text-orange-600"><Upload size={24} /></div>
            <h2 className="text-lg font-bold text-slate-800 mb-2">Restaurar Sistema (JSON)</h2>
            <p className="text-sm text-slate-500 mb-6">Sube un archivo de respaldo (.json) para restaurar el sistema. </p>
            <input type="file" ref={fileInputRef} accept=".json" onChange={handleJsonRestore} className="hidden" />
            <button onClick={() => fileInputRef.current?.click()} disabled={isImporting} className="w-full flex items-center justify-center px-4 py-3 bg-slate-800 hover:bg-slate-900 text-white rounded-lg transition-colors font-medium shadow-sm disabled:opacity-70">{isImporting ? 'Restaurando...' : <><Upload size={18} className="mr-2" /> Subir Respaldo</>}</button>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-red-200 md:col-span-2 relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-1 bg-red-500"></div>
            <div className="flex flex-col md:flex-row gap-8">
                <div className="flex-1">
                    <div className="flex items-center gap-3 mb-4">
                        <div className="w-12 h-12 bg-red-100 rounded-full flex items-center justify-center text-red-600"><RefreshCw size={24} /></div>
                        <div>
                            <h2 className="text-xl font-bold text-slate-900">Carga Híbrida (Reglas + Histórico)</h2>
                            <p className="text-sm text-red-600 font-semibold flex items-center gap-1"><AlertTriangle size={14} /> Reset Total + Estructura + Estado Actual</p>
                        </div>
                    </div>
                    <p className="text-sm text-slate-600 mb-6">Este proceso <b>borra todo</b> y reconstruye el sistema usando reglas de estructura.</p>
                    <div className="space-y-4">
                        <div className="bg-slate-50 p-4 rounded-lg border border-slate-200 hover:border-indigo-300 transition-colors">
                            <div className="flex justify-between items-center mb-2">
                                <span className="text-sm font-bold text-slate-700 flex items-center gap-2"><FileSpreadsheet size={16}/> 1. CSV Reglas (Estructura)</span>
                                {rulesFile ? <span className="text-xs font-bold text-green-600 bg-green-100 px-2 py-0.5 rounded">Cargado</span> : <span className="text-xs text-red-400 font-medium">Requerido</span>}
                            </div>
                            <div className="flex gap-3 items-center">
                                <input type="file" ref={rulesInputRef} accept=".csv,.txt" onChange={(e) => setRulesFile(e.target.files?.[0] || null)} className="hidden" />
                                <button onClick={() => rulesInputRef.current?.click()} className="px-3 py-1.5 bg-white border border-slate-300 text-slate-600 text-xs rounded hover:bg-slate-50 font-medium">Seleccionar Archivo</button>
                                <span className="text-xs text-slate-500 truncate max-w-[200px]">{rulesFile?.name || '...'}</span>
                            </div>
                        </div>
                    </div>
                </div>
                <div className="flex flex-col justify-center items-center md:w-1/3 gap-4 border-l border-slate-100 md:pl-6">
                     <label className="flex items-start gap-2 text-xs text-slate-600 cursor-pointer p-2 rounded hover:bg-slate-50 w-full">
                        <input type="checkbox" checked={userConfirmed} onChange={(e) => setUserConfirmed(e.target.checked)} disabled={isResetting} className="peer h-4 w-4 rounded border-slate-300" />
                        <span>Confirmo <b>eliminar datos</b> y recargar.</span>
                     </label>
                     <button onClick={handleExecuteReset} disabled={isResetting || !rulesFile || !userConfirmed} className={`w-full flex items-center justify-center px-4 py-3 rounded-lg transition-all font-bold shadow-md text-white text-sm ${(rulesFile && userConfirmed) ? 'bg-red-600 hover:bg-red-700' : 'bg-slate-300'}`}>
                        {isResetting ? <span className="flex items-center animate-pulse"><RefreshCw size={16} className="animate-spin mr-2" /> PROCESANDO...</span> : 'EJECUTAR CARGA'}
                    </button>
                    {isResetting && (
                        <div className="w-full bg-white p-3 rounded-lg border border-red-100 shadow-sm mt-2">
                            <div className="w-full bg-slate-100 rounded-full h-3 overflow-hidden border border-slate-200"><div className="bg-red-500 h-3 transition-all duration-300" style={{ width: `${resetProgress}%` }}></div></div>
                            <p className="text-[10px] text-center text-slate-500 mt-2 truncate">{resetStatus}</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

export default AdminDatabase;

import React, { useState, useEffect, useMemo } from 'react';
import { HierarchyService, generateMatrixId } from '../services/firebaseBackend';
import { FullHierarchy, ProcessNode, User, UserRole } from '../types';
import { 
  FolderTree, ChevronRight, ChevronDown, Plus, X, Edit, Trash2, Network, FolderOpen, FileText, Loader2, Search, Eye, EyeOff, Power, FolderInput
} from 'lucide-react';

interface Props {
    user: User;
}

const AdminHierarchy: React.FC<Props> = ({ user }) => {
  const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
  const [loading, setLoading] = useState(true);
  const [selectedProject, setSelectedProject] = useState<string | null>(null);
  const [selectedMacro, setSelectedMacro] = useState<string | null>(null);
  const [selectedProcess, setSelectedProcess] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [showInactive, setShowInactive] = useState(false);
  const [showAddModal, setShowAddModal] = useState(false);
  const [addLevel, setAddLevel] = useState<'PROJECT' | 'MACRO' | 'PROCESS' | 'MICRO'>('PROJECT');
  const [newItemName, setNewItemName] = useState('');
  const [renameMode, setRenameMode] = useState<{ level: string, oldName: string } | null>(null);
  const [renameValue, setRenameValue] = useState('');
  const [showMoveModal, setShowMoveModal] = useState(false);
  const [moveTarget, setMoveTarget] = useState<{ docId: string, name: string, currentProject: string, currentMacro: string, currentProcess: string } | null>(null);
  const [targetProject, setTargetProject] = useState('');
  const [targetMacro, setTargetMacro] = useState('');
  const [targetProcess, setTargetProcess] = useState('');

  useEffect(() => { loadData(); }, []);

  const loadData = async () => {
    setLoading(true);
    try {
        const h = await HierarchyService.getFullHierarchy();
        setHierarchy(h);
    } catch (e) { console.error("Error loading hierarchy:", e); }
    finally { setLoading(false); }
  };

  const handleAdd = (level: 'PROJECT' | 'MACRO' | 'PROCESS' | 'MICRO') => { setAddLevel(level); setNewItemName(''); setShowAddModal(true); };

  const handleCreateSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!newItemName.trim()) return;
      try {
          let project = selectedProject || newItemName;
          let macro = selectedMacro || (addLevel === 'PROJECT' ? 'General' : newItemName);
          let process = selectedProcess || ((addLevel === 'PROJECT' || addLevel === 'MACRO') ? 'General' : newItemName);
          let micro = (addLevel === 'MICRO') ? newItemName : 'Inicio';
          if (addLevel === 'PROJECT') project = newItemName;
          if (addLevel === 'MACRO') macro = newItemName;
          if (addLevel === 'PROCESS') process = newItemName;
          await HierarchyService.addMicroprocess(project, macro, process, micro, [], ['AS IS', 'FCE', 'PM', 'TO BE']);
          setShowAddModal(false);
          await loadData();
      } catch (err: any) { alert('Error: ' + err.message); }
  };

  const handleToggleStatus = async (id: string, name: string, currentStatus: boolean, e: React.MouseEvent) => {
      e.stopPropagation();
      if (!window.confirm(currentStatus ? `¿Inactivar microproceso "${name}"?` : `¿Reactivar "${name}"?`)) return;
      try { await HierarchyService.toggleProcessStatus(id, currentStatus); await loadData(); } catch (e: any) { alert("Error"); }
  };

  const handleHardDeleteMicro = async (id: string, name: string, e: React.MouseEvent) => {
      e.stopPropagation();
      if (!window.confirm(`¿ELIMINAR definitivamente el microproceso "${name}"?`)) return;
      try { await HierarchyService.deleteMicroprocess(id); await loadData(); } catch (e: any) { alert("Error"); }
  };

  const handleDeleteNode = async (level: 'PROJECT' | 'MACRO' | 'PROCESS', name: string, e: React.MouseEvent) => {
      e.stopPropagation();
      if (!window.confirm(`Está a punto de eliminar el ${level}: "${name}". Esta acción ELIMINARÁ TODO el contenido.`)) return;
      try {
          await HierarchyService.deleteHierarchyNode(level, name, { project: selectedProject || undefined, macro: selectedMacro || undefined });
          await loadData();
      } catch (err: any) { alert("Error"); }
  };

  const handleRenameStart = (level: 'PROJECT' | 'MACRO' | 'PROCESS', oldName: string) => { setRenameMode({ level, oldName }); setRenameValue(oldName); };

  const handleRenameSubmit = async () => {
      if (!renameMode || !renameValue.trim() || renameValue === renameMode.oldName) { setRenameMode(null); return; }
      try {
          await HierarchyService.updateHierarchyNode(renameMode.level as any, renameMode.oldName, renameValue, { project: selectedProject || undefined, macro: selectedMacro || undefined });
          setRenameMode(null); await loadData();
      } catch (e: any) { alert('Error'); }
  };

  const handleMoveStart = (micro: ProcessNode, e: React.MouseEvent) => {
      e.stopPropagation();
      setMoveTarget({ docId: micro.docId, name: micro.name, currentProject: selectedProject || '', currentMacro: selectedMacro || '', currentProcess: selectedProcess || '' });
      setTargetProject(selectedProject || ''); setTargetMacro(selectedMacro || ''); setTargetProcess(selectedProcess || ''); setShowMoveModal(true);
  };

  const handleMoveSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!moveTarget || !targetProject || !targetMacro || !targetProcess) return;
      try {
          await HierarchyService.moveMicroprocess(moveTarget.docId, targetProject, targetMacro, targetProcess);
          setShowMoveModal(false); await loadData();
      } catch (err: any) { alert('Error'); }
  };

  if (loading) return <div className="p-8 text-center text-slate-500"><Loader2 className="animate-spin" /></div>;

  const projects = Object.keys(hierarchy).sort();
  const macros = selectedProject ? Object.keys(hierarchy[selectedProject] || {}).sort() : [];
  const processes = (selectedProject && selectedMacro) ? Object.keys(hierarchy[selectedProject][selectedMacro] || {}).sort() : [];
  const micros = (selectedProject && selectedMacro && selectedProcess) ? hierarchy[selectedProject][selectedMacro][selectedProcess].filter(m => showInactive || m.active !== false) : [];

  return (
    <div className="space-y-6 pb-12">
      <div className="flex justify-between items-center">
          <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2"><Network className="text-indigo-600" /> Estructura</h1>
          <button onClick={() => setShowInactive(!showInactive)} className="text-xs font-bold border p-2 rounded-lg">{showInactive ? 'Ocultar Inactivos' : 'Ver Inactivos'}</button>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 h-[calc(100vh-220px)]">
          <Column title="Proyectos" items={projects} selected={selectedProject} onSelect={(p) => {setSelectedProject(p); setSelectedMacro(null); setSelectedProcess(null);}} onAdd={() => handleAdd('PROJECT')} onRename={(p) => handleRenameStart('PROJECT', p)} onDelete={(p) => handleDeleteNode('PROJECT', p, null as any)} />
          <Column title="Macros" items={macros} selected={selectedMacro} onSelect={(m) => {setSelectedMacro(m); setSelectedProcess(null);}} onAdd={() => handleAdd('MACRO')} onRename={(m) => handleRenameStart('MACRO', m)} onDelete={(m) => handleDeleteNode('MACRO', m, null as any)} disabled={!selectedProject} />
          <Column title="Procesos" items={processes} selected={selectedProcess} onSelect={setSelectedProcess} onAdd={() => handleAdd('PROCESS')} onRename={(pr) => handleRenameStart('PROCESS', pr)} onDelete={(pr) => handleDeleteNode('PROCESS', pr, null as any)} disabled={!selectedMacro} />
          <div className={`bg-white rounded-xl shadow-sm border border-slate-200 flex flex-col overflow-hidden ${!selectedProcess ? 'opacity-50 pointer-events-none' : ''}`}>
              <div className="p-3 border-b bg-slate-50 flex justify-between items-center"><h3 className="font-bold text-xs uppercase">Microprocesos</h3><button onClick={() => handleAdd('MICRO')} className="p-1 text-indigo-600"><Plus size={16}/></button></div>
              <div className="flex-1 overflow-y-auto p-2 space-y-1">
                  {micros.map(m => (
                      <div key={m.docId} className="flex items-center justify-between p-2 rounded-lg text-sm bg-white border group">
                          <span className="truncate font-medium">{m.name}</span>
                          <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100">
                              <button onClick={(e) => handleMoveStart(m, e)} className="p-1 text-slate-400 hover:text-indigo-600"><FolderInput size={14}/></button>
                              <button onClick={(e) => handleToggleStatus(m.docId, m.name, m.active !== false, e)} className="p-1 text-slate-400"><Power size={14}/></button>
                              <button onClick={(e) => handleHardDeleteMicro(m.docId, m.name, e)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={14}/></button>
                          </div>
                      </div>
                  ))}
              </div>
          </div>
      </div>
      {showAddModal && <Modal title={`Agregar ${addLevel}`} value={newItemName} onChange={setNewItemName} onCancel={() => setShowAddModal(false)} onSubmit={handleCreateSubmit} />}
      {renameMode && <Modal title={`Renombrar ${renameMode.level}`} value={renameValue} onChange={setRenameValue} onCancel={() => setRenameMode(null)} onSubmit={handleRenameSubmit} />}
    </div>
  );
};

const Column = ({ title, items, selected, onSelect, onAdd, onRename, onDelete, disabled }: any) => (
    <div className={`bg-white rounded-xl shadow-sm border border-slate-200 flex flex-col overflow-hidden ${disabled ? 'opacity-50 pointer-events-none' : ''}`}>
        <div className="p-3 border-b bg-slate-50 flex justify-between items-center"><h3 className="font-bold text-xs uppercase">{title}</h3><button onClick={onAdd} className="p-1 text-indigo-600"><Plus size={16}/></button></div>
        <div className="flex-1 overflow-y-auto p-2 space-y-1">
            {items.map((item: string) => (
                <div key={item} onClick={() => onSelect(item)} className={`flex items-center justify-between p-2 rounded-lg cursor-pointer text-sm group ${selected === item ? 'bg-indigo-50 text-indigo-700 font-bold' : 'hover:bg-slate-50'}`}>
                    <span className="truncate">{item}</span>
                    <div className="flex gap-1 opacity-0 group-hover:opacity-100">
                        <button onClick={(e) => {e.stopPropagation(); onRename(item);}} className="text-slate-400"><Edit size={12}/></button>
                        <button onClick={(e) => {e.stopPropagation(); onDelete(item);}} className="text-slate-400 hover:text-red-600"><Trash2 size={12}/></button>
                    </div>
                </div>
            ))}
        </div>
    </div>
);

const Modal = ({ title, value, onChange, onCancel, onSubmit }: any) => (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
        <div className="bg-white rounded-xl shadow-xl w-full max-w-md p-6">
            <h3 className="font-bold text-lg mb-4">{title}</h3>
            <input autoFocus value={value} onChange={(e) => onChange(e.target.value)} className="w-full p-2 border rounded-lg mb-6" />
            <div className="flex justify-end gap-2"><button onClick={onCancel} className="px-4 py-2 text-slate-600">Cancelar</button><button onClick={onSubmit} className="px-4 py-2 bg-indigo-600 text-white rounded-lg">Guardar</button></div>
        </div>
    </div>
);

export default AdminHierarchy;

import React, { useState, useEffect, useMemo } from 'react';
import { ReferentService, HierarchyService } from '../services/firebaseBackend';
import { Referent, FullHierarchy, ProcessNode, User, UserRole, UserHierarchy } from '../types';
import { 
    UserPlus, Search, Edit, Trash2, X, Save, Building, Mail, Briefcase, 
    Loader2, AlertCircle, FolderTree, Network, CheckSquare, ChevronRight, Lock
} from 'lucide-react';

interface Props {
    user: User;
}

const AdminReferents: React.FC<Props> = ({ user }) => {
    const [referents, setReferents] = useState<Referent[]>([]);
    const [fullHierarchy, setFullHierarchy] = useState<FullHierarchy>({});
    const [userHierarchy, setUserHierarchy] = useState<UserHierarchy | null>(null);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [showForm, setShowForm] = useState(false);
    const [editingId, setEditingId] = useState<string | null>(null);
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [specialty, setSpecialty] = useState('');
    const [organization, setOrganization] = useState('');
    const [linkProject, setLinkProject] = useState('');
    const [linkMacro, setLinkMacro] = useState('');
    const [linkProcess, setLinkProcess] = useState('');
    const [linkMicroSearch, setLinkMicroSearch] = useState('');
    const [selectedMicroIds, setSelectedMicroIds] = useState<string[]>([]);

    const isAnalyst = user.role === UserRole.ANALYST;

    useEffect(() => { loadData(); }, [user.id]);

    const loadData = async () => {
        setLoading(true);
        try {
            const [r, fh] = await Promise.all([ReferentService.getAll(), HierarchyService.getFullHierarchy()]);
            setFullHierarchy(fh);
            if (isAnalyst) {
                const uh = await HierarchyService.getUserHierarchy(user.id);
                setUserHierarchy(uh);
                const userProjects = Object.keys(uh);
                setReferents(r.filter(ref => userProjects.includes(ref.organization)));
            } else { setReferents(r); setUserHierarchy(null); }
        } catch (e) { console.error(e); } finally { setLoading(false); }
    };

    const handleEdit = (r: Referent) => {
        setEditingId(r.id); setName(r.name); setEmail(r.email); setSpecialty(r.specialty); setOrganization(r.organization);
        const linkedIds: string[] = [];
        Object.keys(fullHierarchy).forEach(proj => {
            Object.keys(fullHierarchy[proj]).forEach(macro => {
                Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                    fullHierarchy[proj][macro][proc].forEach(node => {
                        if (node.referentIds?.includes(r.id)) linkedIds.push(node.docId);
                    });
                });
            });
        });
        setSelectedMicroIds(linkedIds); setShowForm(true);
    };

    const resetForm = () => {
        setEditingId(null); setName(''); setEmail(''); setSpecialty(''); setOrganization('');
        setLinkProject(''); setLinkMacro(''); setLinkProcess(''); setLinkMicroSearch(''); setSelectedMicroIds([]);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        const data = { name, email, specialty, organization };
        try {
            let refId = editingId;
            if (editingId) { await ReferentService.update(editingId, data); } 
            else { const newRef = await ReferentService.create(data); refId = newRef.id; }
            if (refId) { await HierarchyService.updateReferentLinks(refId, selectedMicroIds); }
            setShowForm(false); resetForm(); await loadData();
        } catch (e) { alert("Error"); }
    };

    const handleDelete = async (id: string) => {
        if (!window.confirm("¿Eliminar referente?")) return;
        try { await ReferentService.delete(id); await loadData(); } catch (e) { alert("Error"); }
    };

    const filteredMicros = useMemo(() => {
        let list: { project: string, macro: string, process: string, node: ProcessNode }[] = [];
        Object.keys(fullHierarchy).forEach(proj => {
            if (isAnalyst && userHierarchy && !userHierarchy[proj]) return;
            if (linkProject && proj !== linkProject) return;
            Object.keys(fullHierarchy[proj]).forEach(macro => {
                if (linkMacro && macro !== linkMacro) return;
                Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                    if (linkProcess && proc !== linkProcess) return;
                    fullHierarchy[proj][macro][proc].forEach(node => {
                        if (isAnalyst && userHierarchy && (!userHierarchy[proj][macro] || !userHierarchy[proj][macro][proc] || !userHierarchy[proj][macro][proc].includes(node.name))) return;
                        if (!linkMicroSearch || node.name.toLowerCase().includes(linkMicroSearch.toLowerCase())) list.push({ project: proj, macro, process: proc, node });
                    });
                });
            });
        });
        return list;
    }, [fullHierarchy, userHierarchy, isAnalyst, linkProject, linkMacro, linkProcess, linkMicroSearch]);

    if (loading) return <div className="p-8 text-center"><Loader2 className="animate-spin mx-auto" /></div>;

    return (
        <div className="space-y-6 pb-12">
            <div className="flex justify-between items-center">
                <div><h1 className="text-2xl font-bold">Referentes</h1><p className="text-slate-500">Gestión de expertos técnicos.</p></div>
                <button onClick={() => { resetForm(); setShowForm(true); }} className="px-4 py-2 bg-indigo-600 text-white rounded-lg font-medium"><UserPlus size={18} className="inline mr-2" /> Nuevo Referente</button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {referents.map(r => (
                    <div key={r.id} className="bg-white rounded-xl shadow-sm border p-5 group">
                        <div className="flex justify-between mb-4"><div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center font-bold">{r.name.charAt(0)}</div>
                            <div className="flex gap-1 opacity-0 group-hover:opacity-100"><button onClick={() => handleEdit(r)} className="p-1 text-slate-400 hover:text-indigo-600"><Edit size={16}/></button><button onClick={() => handleDelete(r.id)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={16}/></button></div>
                        </div>
                        <h3 className="font-bold">{r.name}</h3><p className="text-xs text-slate-500">{r.specialty}</p><p className="text-xs text-slate-400 mt-2">{r.email}</p>
                    </div>
                ))}
            </div>
            {showForm && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
                    <div className="bg-white rounded-xl shadow-xl w-full max-w-4xl p-6">
                        <h3 className="text-lg font-bold mb-6">{editingId ? 'Editar' : 'Nuevo'} Referente</h3>
                        <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            <div className="space-y-4">
                                <input placeholder="Nombre" value={name} onChange={(e) => setName(e.target.value)} className="w-full p-2 border rounded" required />
                                <input placeholder="Email" type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full p-2 border rounded" required />
                                <input placeholder="Especialidad" value={specialty} onChange={(e) => setSpecialty(e.target.value)} className="w-full p-2 border rounded" required />
                                <select value={organization} onChange={(e) => setOrganization(e.target.value)} className="w-full p-2 border rounded" required><option value="">Proyecto</option>{Object.keys(fullHierarchy).map(p => <option key={p} value={p}>{p}</option>)}</select>
                            </div>
                            <div className="space-y-4 flex flex-col h-full">
                                <h4 className="font-bold text-sm">Vincular Microprocesos</h4>
                                <div className="flex-1 overflow-y-auto border p-2 bg-slate-50 max-h-[300px]">
                                    {filteredMicros.map(item => (
                                        <label key={item.node.docId} className="flex items-center gap-2 p-1 hover:bg-white cursor-pointer text-xs">
                                            <input type="checkbox" checked={selectedMicroIds.includes(item.node.docId)} onChange={() => setSelectedMicroIds(prev => prev.includes(item.node.docId) ? prev.filter(id => id !== item.node.docId) : [...prev, item.node.docId])} />
                                            <span>{item.node.name}</span>
                                        </label>
                                    ))}
                                </div>
                            </div>
                            <div className="md:col-span-2 flex justify-end gap-3"><button type="button" onClick={() => setShowForm(false)} className="px-4 py-2">Cancelar</button><button type="submit" className="px-6 py-2 bg-indigo-600 text-white rounded-lg">Guardar</button></div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default AdminReferents;

import React, { useState, useEffect } from 'react';
import { UserService } from '../services/firebaseBackend';
import { User, UserRole } from '../types';
import { Trash2, UserPlus, Shield, X, Pencil, Power, PieChart, UserCheck, Loader2 } from 'lucide-react';

const AdminUsers: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingUserId, setEditingUserId] = useState<string | null>(null);
  const [updatingId, setUpdatingId] = useState<string | null>(null);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [nickname, setNickname] = useState('');
  const [role, setRole] = useState<UserRole>(UserRole.ANALYST);
  const [organization, setOrganization] = useState('');
  const [password, setPassword] = useState('');
  const [canAccessReports, setCanAccessReports] = useState(false);
  const [canAccessReferents, setCanAccessReferents] = useState(false);

  useEffect(() => { loadUsers(); }, []);

  const loadUsers = async () => { setLoading(true); const data = await UserService.getAll(); setUsers(data); setLoading(false); };

  const handleTogglePermission = async (user: User, field: 'canAccessReports' | 'canAccessReferents') => {
      setUpdatingId(`${user.id}-${field}`);
      const newValue = !user[field];
      try { await UserService.update(user.id, { [field]: newValue }); setUsers(prev => prev.map(u => u.id === user.id ? { ...u, [field]: newValue } : u)); } 
      catch (error) { alert('Error'); } finally { setUpdatingId(null); }
  };

  const handleDelete = async (id: string) => {
    if (!window.confirm('¿Eliminar usuario?')) return;
    try { await UserService.delete(id); await loadUsers(); } catch (error) { console.error(error); }
  };

  const handleToggleStatus = async (user: User) => {
      if (!window.confirm(`¿Cambiar estado de ${user.name}?`)) return;
      try { await UserService.toggleActiveStatus(user.id, user.active !== false); await loadUsers(); } catch (error) { alert('Error'); }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
        if (editingUserId) {
            await UserService.update(editingUserId, { name, email, nickname, role, organization, password: password || undefined, canAccessReports: role === UserRole.ANALYST ? canAccessReports : true, canAccessReferents: role === UserRole.ANALYST ? canAccessReferents : true });
        } else {
            await UserService.create({ id: `user-${Date.now()}`, name, email, nickname, role, organization, password: password || undefined, active: true, canAccessReports: role === UserRole.ANALYST ? canAccessReports : true, canAccessReferents: role === UserRole.ANALYST ? canAccessReferents : true } as User);
        }
        setShowForm(false); setEditingUserId(null); await loadUsers();
    } catch (err: any) { alert(err.message); }
  };

  return (
    <div className="space-y-6">
        <div className="flex justify-between items-center">
            <h1 className="text-2xl font-bold">Usuarios</h1>
            <button onClick={() => setShowForm(!showForm)} className="px-4 py-2 bg-indigo-600 text-white rounded-lg">{showForm ? 'Cancelar' : 'Nuevo Usuario'}</button>
        </div>
        {showForm && (
            <form onSubmit={handleSubmit} className="bg-white p-6 rounded-xl border grid grid-cols-1 md:grid-cols-2 gap-4">
                <input placeholder="Nombre" value={name} onChange={(e) => setName(e.target.value)} className="p-2 border rounded" required />
                <input placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} className="p-2 border rounded" required />
                <input placeholder="Nickname" value={nickname} onChange={(e) => setNickname(e.target.value)} className="p-2 border rounded" />
                <input placeholder="Password" type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="p-2 border rounded" />
                <input placeholder="Organización" value={organization} onChange={(e) => setOrganization(e.target.value)} className="p-2 border rounded" required />
                <select value={role} onChange={(e) => setRole(e.target.value as UserRole)} className="p-2 border rounded"><option value={UserRole.ANALYST}>Analista</option><option value={UserRole.COORDINATOR}>Coordinador</option><option value={UserRole.ADMIN}>Administrador</option></select>
                <div className="md:col-span-2 flex justify-end"><button type="submit" className="px-6 py-2 bg-indigo-600 text-white rounded-lg">Guardar</button></div>
            </form>
        )}
        <div className="bg-white rounded-xl border overflow-x-auto">
            <table className="w-full text-sm text-left">
                <thead className="bg-slate-50 uppercase text-[10px] font-bold"><tr><th className="p-4">Usuario</th><th className="p-4">Estado</th><th className="p-4">Rol</th><th className="p-4 text-right">Acciones</th></tr></thead>
                <tbody>
                    {users.map(u => (
                        <tr key={u.id} className="border-t hover:bg-slate-50 transition-colors">
                            <td className="p-4"><p className="font-bold">{u.name}</p><p className="text-xs text-slate-500">{u.email}</p></td>
                            <td className="p-4"><span className={`px-2 py-0.5 rounded-full text-[10px] font-bold ${u.active !== false ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-500'}`}>{u.active !== false ? 'Activo' : 'Inactivo'}</span></td>
                            <td className="p-4"><span className="text-xs font-medium">{u.role}</span></td>
                            <td className="p-4 text-right">
                                <button onClick={() => handleToggleStatus(u)} className="p-1 text-slate-400 hover:text-red-600"><Power size={18}/></button>
                                <button onClick={() => handleDelete(u.id)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={18}/></button>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    </div>
  );
};

