import React, { useEffect, useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { NotificationService } from '../services/firebaseBackend';
import { User, Notification } from '../types';
import { Inbox, CheckCircle, Mail, User as UserIcon, MessageSquare, AlertTriangle, CheckSquare, ArrowRight, Search, ChevronLeft, ChevronRight } from 'lucide-react';

const Buffer: React.FC<{user: User}> = ({ user }) => {
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'UNREAD' | 'ALL'>('UNREAD');
  const [searchTerm, setSearchTerm] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const navigate = useNavigate();

  useEffect(() => { loadNotifications(); }, []);

  const loadNotifications = async () => {
    setLoading(true);
    const data = await NotificationService.getByUser(user.id);
    setNotifications(data);
    if (!data.some(n => !n.isRead) && data.length > 0) setActiveTab('ALL');
    setLoading(false);
  };

  const handleItemClick = async (notif: Notification) => {
      if (!notif.isRead) { await NotificationService.markAsRead(notif.id); setNotifications(prev => prev.map(n => n.id === notif.id ? { ...n, isRead: true } : n)); }
      navigate(notif.documentId.startsWith('MTX_') ? '/new' : `/doc/${notif.documentId}`);
  };

  const filtered = useMemo(() => notifications.filter(n => (activeTab === 'UNREAD' ? !n.isRead : true) && (!searchTerm || n.title.toLowerCase().includes(searchTerm.toLowerCase()))), [notifications, activeTab, searchTerm]);
  const paginated = filtered.slice((currentPage - 1) * 5, currentPage * 5);

  if (loading) return <div className="p-8 text-center">Cargando...</div>;

  return (
    <div className="space-y-6 max-w-4xl mx-auto pb-12">
      <div className="flex justify-between items-center">
        <h1 className="text-2xl font-bold flex items-center gap-2"><Inbox className="text-indigo-600" /> Bandeja</h1>
        {notifications.some(n => !n.isRead) && <button onClick={async () => { await NotificationService.markAllAsRead(user.id); loadNotifications(); }} className="text-xs font-bold text-indigo-600">Marcar todo leído</button>}
      </div>
      <div className="bg-white rounded-xl shadow-sm border overflow-hidden flex flex-col min-h-[400px]">
          <div className="p-4 border-b flex justify-between gap-4">
              <div className="flex bg-slate-100 p-1 rounded-lg">
                  <button onClick={() => setActiveTab('UNREAD')} className={`px-4 py-1.5 rounded-md text-xs font-bold ${activeTab === 'UNREAD' ? 'bg-white shadow-sm' : 'text-slate-500'}`}>Pendientes</button>
                  <button onClick={() => setActiveTab('ALL')} className={`px-4 py-1.5 rounded-md text-xs font-bold ${activeTab === 'ALL' ? 'bg-white shadow-sm' : 'text-slate-500'}`}>Todos</button>
              </div>
              <input placeholder="Buscar..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="border rounded-lg px-3 text-sm outline-none" />
          </div>
          <div className="divide-y">
            {paginated.map(n => (
                <div key={n.id} onClick={() => handleItemClick(n)} className={`p-4 hover:bg-slate-50 cursor-pointer flex gap-4 ${!n.isRead ? 'bg-indigo-50/20' : ''}`}>
                    <div className="mt-1">{n.type === 'ASSIGNMENT' ? <UserIcon size={18} className="text-blue-500"/> : <Mail size={18}/>}</div>
                    <div className="flex-1"><h4 className={`text-sm ${!n.isRead ? 'font-bold' : ''}`}>{n.title}</h4><p className="text-xs text-slate-500 line-clamp-1">{n.message}</p></div>
                    <span className="text-[10px] text-slate-400">{new Date(n.timestamp).toLocaleDateString()}</span>
                </div>
            ))}
          </div>
      </div>
    </div>
  );
};

export default Buffer;

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { User, DocState, DocType, UserHierarchy, UserRole, Document, FullHierarchy } from '../types';
import { parseDocumentFilename } from '../utils/filenameParser';
import { Save, ArrowLeft, Upload, FileCheck, FileX, Info, ListFilter, Lock, RefreshCw } from 'lucide-react';

const CreateDocument: React.FC<{user: User}> = ({ user }) => {
  const navigate = useNavigate();
  const location = useLocation(); 
  const [loading, setLoading] = useState(false);
  const [initializing, setInitializing] = useState(true);
  const [userHierarchy, setUserHierarchy] = useState<UserHierarchy>({});
  const [fullHierarchyCache, setFullHierarchyCache] = useState<FullHierarchy>({}); 
  const [requirementsMap, setRequirementsMap] = useState<Record<string, DocType[]>>({});
  const [selectedProject, setSelectedProject] = useState('');
  const [selectedMacro, setSelectedMacro] = useState('');
  const [selectedProcess, setSelectedProcess] = useState('');
  const [selectedMicro, setSelectedMicro] = useState('');
  const [selectedDocType, setSelectedDocType] = useState<DocType | ''>('');
  const [requestType, setRequestType] = useState('');
  const [file, setFile] = useState<File | undefined>(undefined);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('0.0');
  const [detectedState, setDetectedState] = useState<DocState>(DocState.INITIATED);

  useEffect(() => { loadData(); }, []);

  const loadData = async () => {
      try {
          const [reqMap, full] = await Promise.all([HierarchyService.getRequiredTypesMap(), HierarchyService.getFullHierarchy()]);
          setRequirementsMap(reqMap);
          setFullHierarchyCache(full);
          const tree: UserHierarchy = {};
          Object.keys(full).forEach(p => {
              tree[p] = {};
              Object.keys(full[p]).forEach(m => {
                  tree[p][m] = {};
                  Object.keys(full[p][m]).forEach(proc => { tree[p][m][proc] = full[p][m][proc].map(n => n.name); });
              });
          });
          setUserHierarchy(tree);
          if (location.state?.prefill) {
              const { project, macro, process, micro, docType } = location.state.prefill;
              setSelectedProject(project); setSelectedMacro(macro); setSelectedProcess(process); setSelectedMicro(micro); setSelectedDocType(docType);
          }
      } finally { setInitializing(false); }
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0]) {
          const f = e.target.files[0]; setFile(f);
          const res = parseDocumentFilename(f.name, selectedProject, selectedMicro, selectedDocType || undefined, requestType as any);
          if (res.valido) {
              setIsFileValid(true); setFileError([]); setDetectedVersion(res.nomenclatura || '0.0');
              if (res.estado) setDetectedState(res.estado === 'Aprobado' ? DocState.APPROVED : DocState.IN_PROCESS);
          } else { setIsFileValid(false); setFileError(res.errores); }
      }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!file || !isFileValid) return;
    setLoading(true);
    try {
      const nodes = fullHierarchyCache[selectedProject]?.[selectedMacro]?.[selectedProcess] || [];
      const node = nodes.find(n => n.name === selectedMicro);
      await DocumentService.create(file.name, 'Carga de documento', user, detectedState, detectedVersion, 10, file, { project: selectedProject, macro: selectedMacro, process: selectedProcess, micro: selectedMicro, docType: selectedDocType, assignees: node?.assignees });
      navigate('/');
    } catch (error) { alert('Error'); } finally { setLoading(false); }
  };

  if (initializing) return <div className="p-8 text-center">Iniciando...</div>;

  return (
    <div className="max-w-3xl mx-auto pb-12">
        <h1 className="text-2xl font-bold mb-6">Nueva Solicitud</h1>
        <form onSubmit={handleSubmit} className="space-y-6 bg-white p-6 rounded-xl border">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <select value={selectedProject} onChange={(e) => setSelectedProject(e.target.value)} className="p-2 border rounded"><option value="">Proyecto</option>{Object.keys(userHierarchy).map(p => <option key={p} value={p}>{p}</option>)}</select>
                <select value={selectedMacro} onChange={(e) => setSelectedMacro(e.target.value)} className="p-2 border rounded"><option value="">Macro</option>{selectedProject && Object.keys(userHierarchy[selectedProject] || {}).map(m => <option key={m} value={m}>{m}</option>)}</select>
                <select value={selectedProcess} onChange={(e) => setSelectedProcess(e.target.value)} className="p-2 border rounded"><option value="">Proceso</option>{selectedMacro && Object.keys(userHierarchy[selectedProject][selectedMacro] || {}).map(pr => <option key={pr} value={pr}>{pr}</option>)}</select>
                <select value={selectedMicro} onChange={(e) => setSelectedMicro(e.target.value)} className="p-2 border rounded"><option value="">Microproceso</option>{selectedProcess && userHierarchy[selectedProject][selectedMacro][selectedProcess].map(m => <option key={m} value={m}>{m}</option>)}</select>
            </div>
            <select value={selectedDocType} onChange={(e) => setSelectedDocType(e.target.value as DocType)} className="w-full p-2 border rounded"><option value="">Tipo de Informe</option>{['AS IS', 'FCE', 'PM', 'TO BE'].map(t => <option key={t} value={t}>{t}</option>)}</select>
            <select value={requestType} onChange={(e) => setRequestType(e.target.value)} className="w-full p-2 border rounded"><option value="">Etapa</option><option value="INITIATED">Iniciado (0.0)</option><option value="IN_PROCESS">En Proceso (0.n)</option><option value="INTERNAL">Revisión Interna (v0.n)</option></select>
            <div className="border-2 border-dashed p-8 text-center rounded-lg relative">
                <input type="file" onChange={handleFileSelect} className="absolute inset-0 opacity-0 cursor-pointer" />
                {file ? <p className={isFileValid ? 'text-green-600' : 'text-red-600'}>{file.name}</p> : <p>Arrastra o haz click aquí</p>}
            </div>
            {fileError.length > 0 && <ul className="text-xs text-red-500">{fileError.map((e,i) => <li key={i}>{e}</li>)}</ul>}
            <button type="submit" disabled={!isFileValid || loading} className="w-full bg-indigo-600 text-white p-3 rounded-lg font-bold disabled:opacity-50">Cargar Documento</button>
        </form>
    </div>
  );
};

export default CreateDocument;

import React, { useEffect, useState, useMemo } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, UserRole, DocState, DocType, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    Plus, Clock, CheckCircle, Filter, X, Activity, 
    BookOpen, Users, ShieldCheck, ArrowUp, ArrowDown, ArrowUpDown, Loader2,
    User as UserIcon, Database, Archive, Search,
    ChevronLeft, ChevronRight, FileSpreadsheet, ListTodo, Layers
} from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface DashboardDoc extends Document {
    isRequired: boolean;
}

const Dashboard: React.FC<{user: User}> = ({ user }) => {
  const navigate = useNavigate();
  const location = useLocation(); 
  const [mergedDocs, setMergedDocs] = useState<DashboardDoc[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [filterProject, setFilterProject] = useState('');
  const [filterSearch, setFilterSearch] = useState(''); 
  const [quickFilter, setQuickFilter] = useState('ALL');
  const [currentPage, setCurrentPage] = useState(1);

  useEffect(() => { loadData(); }, [location.state]);

  const loadData = async () => {
    setLoading(true);
    try {
        const [realDocs, users, fullHierarchy] = await Promise.all([DocumentService.getAll(), UserService.getAll(), HierarchyService.getFullHierarchy()]);
        setAllUsers(users);
        const finalDocs: DashboardDoc[] = [];
        const realDocMap = new Map<string, Document>();
        realDocs.forEach(d => {
            const key = `${normalizeHeader(d.project || '')}|${normalizeHeader(d.microprocess || '')}|${normalizeHeader(d.docType || '')}`;
            realDocMap.set(key, d);
        });

        Object.keys(fullHierarchy).forEach(proj => {
            Object.keys(fullHierarchy[proj]).forEach(macro => {
                Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                    fullHierarchy[proj][macro][proc].forEach(node => {
                        if (node.active === false) return;
                        node.requiredTypes?.forEach(type => {
                            const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;
                            if (realDocMap.has(key)) {
                                finalDocs.push({ ...realDocMap.get(key)!, macroprocess: macro, process: proc, project: proj, isRequired: true });
                            } else {
                                finalDocs.push({ id: `virtual-${key}`, title: `${node.name} - ${type}`, microprocess: node.name, docType: type, state: DocState.NOT_STARTED, project: proj, macroprocess: macro, process: proc, authorId: '', authorName: '', assignees: node.assignees || [], version: '-', progress: 0, files: [], createdAt: '', updatedAt: '', isRequired: true });
                            }
                        });
                    });
                });
            });
        });
        setMergedDocs(finalDocs);
    } finally { setLoading(false); }
  };

  const filtered = useMemo(() => {
      let docs = mergedDocs;
      if (filterProject) docs = docs.filter(d => d.project === filterProject);
      if (filterSearch) docs = docs.filter(d => d.title.toLowerCase().includes(filterSearch.toLowerCase()));
      if (quickFilter !== 'ALL') {
          if (quickFilter === 'FINISHED') docs = docs.filter(d => d.state === DocState.APPROVED);
          else if (quickFilter === 'NOT_STARTED') docs = docs.filter(d => d.state === DocState.NOT_STARTED);
      }
      return docs;
  }, [mergedDocs, filterProject, filterSearch, quickFilter]);

  if (loading) return <div className="p-8 text-center">Cargando tablero...</div>;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex justify-between items-center">
          <h1 className="text-2xl font-bold">Dashboard</h1>
          <div className="flex gap-2">
              <input placeholder="Buscar..." value={filterSearch} onChange={(e) => setFilterSearch(e.target.value)} className="border rounded px-2 text-sm" />
              <Link to="/new" className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-bold">Nueva Solicitud</Link>
          </div>
      </div>
      <div className="bg-white rounded-xl shadow-sm border overflow-x-auto">
          <table className="w-full text-sm text-left">
              <thead className="bg-slate-50 uppercase text-[10px] font-bold"><tr><th className="p-4">Proyecto</th><th className="p-4">Microproceso</th><th className="p-4">Documento</th><th className="p-4">Estado</th><th className="p-4 text-right">Actualizado</th></tr></thead>
              <tbody className="divide-y">
                  {filtered.slice((currentPage - 1) * 10, currentPage * 10).map(doc => (
                      <tr key={doc.id} onClick={() => navigate(`/doc/${doc.id}`)} className="hover:bg-slate-50 cursor-pointer">
                          <td className="p-4 font-bold">{doc.project}</td>
                          <td className="p-4">{doc.microprocess}</td>
                          <td className="p-4"><span className="bg-indigo-50 text-indigo-700 px-2 py-0.5 rounded text-[10px] font-bold">{doc.docType}</span></td>
                          <td className="p-4"><span className={`px-2 py-1 rounded-full text-[10px] font-bold ${STATE_CONFIG[doc.state].color}`}>{STATE_CONFIG[doc.state].label.split('(')[0]}</span></td>
                          <td className="p-4 text-right text-xs text-slate-400">{doc.updatedAt ? new Date(doc.updatedAt).toLocaleDateString() : '-'}</td>
                      </tr>
                  ))}
              </tbody>
          </table>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon: Icon, color, isActive, onClick }: any) => (
    <div onClick={onClick} className={`p-4 rounded-xl shadow-sm border cursor-pointer transition-all ${isActive ? 'ring-2 ring-indigo-300' : ''} ${color}`}>
        <Icon size={20} className="mb-2" />
        <p className="text-[10px] uppercase font-bold opacity-70">{title}</p>
        <p className="text-xl font-bold">{value}</p>
    </div>
);

export default Dashboard;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, ReferentService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy, Referent } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, MessageSquare, PlusCircle, Trash2, Info, Upload } from 'lucide-react';

const DocumentDetail: React.FC<{user: User}> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation(); 
  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');

  useEffect(() => { loadData(); }, [id]);

  const loadData = async () => {
      if (!id) return;
      setLoading(true);
      try {
          const d = await DocumentService.getById(id);
          if (d) { setDoc(d); const h = await HistoryService.getHistory(id); setHistory(h); }
      } finally { setLoading(false); }
  };

  const handleActionClick = (action: 'APPROVE' | 'REJECT' | 'COMMENT') => {
      if (!doc) return;
      if (action === 'COMMENT') { executeTransition('COMMENT', comment); return; }
      setPendingAction(action); setResponseFile(null); setFileError([]); setIsFileValid(false); setShowResponseModal(true);
  };

  const handleResponseFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && doc && pendingAction) {
          const f = e.target.files[0]; setResponseFile(f);
          const res = parseDocumentFilename(f.name, doc.project, doc.microprocess, doc.docType);
          if (!res.valido) { setFileError(res.errores); setIsFileValid(false); return; }
          const rules = validateCoordinatorRules(f.name, doc.version, doc.state, pendingAction);
          if (!rules.valid) { setFileError([rules.error || 'Error de versión']); setIsFileValid(false); return; }
          setIsFileValid(true); setFileError([]); setDetectedVersion(res.nomenclatura || '');
      }
  };

  const executeTransition = async (action: any, c: string, f?: File, v?: string) => {
      if (!doc) return;
      try { await DocumentService.transitionState(doc.id, user, action, c, f, v); setComment(''); await loadData(); } catch (e) { alert("Error"); }
  };

  if (loading) return <div className="p-8 text-center">Cargando...</div>;
  if (!doc) return <div className="p-8 text-center">No encontrado</div>;

  return (
    <div className="max-w-4xl mx-auto space-y-6 pb-12">
      <div className="flex justify-between items-center"><button onClick={() => navigate(-1)} className="text-sm text-slate-500 flex items-center gap-1"><ArrowLeft size={16}/> Volver</button></div>
      <div className="bg-white p-6 rounded-xl border shadow-sm">
          <div className="flex justify-between items-start mb-4">
              <div><h1 className="text-2xl font-bold">{doc.title}</h1><p className="text-slate-500">{doc.description}</p></div>
              <span className={`px-3 py-1 rounded-lg text-xs font-bold ${STATE_CONFIG[doc.state].color}`}>{STATE_CONFIG[doc.state].label}</span>
          </div>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-xs border-t pt-4">
              <div><p className="text-slate-400 uppercase font-bold">Versión</p><p className="font-bold">{doc.version}</p></div>
              <div><p className="text-slate-400 uppercase font-bold">Estado</p><p>{STATE_CONFIG[doc.state].label.split('(')[0]}</p></div>
              <div><p className="text-slate-400 uppercase font-bold">Analista</p><p>{doc.authorName}</p></div>
              <div><p className="text-slate-400 uppercase font-bold">Fecha</p><p>{new Date(doc.updatedAt).toLocaleDateString()}</p></div>
          </div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="md:col-span-2 space-y-6">
              <div className="bg-white p-6 rounded-xl border">
                  <h3 className="font-bold mb-4">Gestión de Flujo</h3>
                  <textarea value={comment} onChange={(e) => setComment(e.target.value)} placeholder="Comentarios..." className="w-full p-2 border rounded-lg mb-4 h-24 text-sm" />
                  <div className="flex flex-wrap gap-2">
                      <button onClick={() => handleActionClick('COMMENT')} className="px-4 py-2 bg-slate-800 text-white rounded-lg text-sm">Guardar Observación</button>
                      {(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) && (
                          <><button onClick={() => handleActionClick('APPROVE')} className="px-4 py-2 bg-green-600 text-white rounded-lg text-sm">Aprobar</button>
                            <button onClick={() => handleActionClick('REJECT')} className="px-4 py-2 bg-red-600 text-white rounded-lg text-sm">Rechazar</button></>
                      )}
                  </div>
              </div>
          </div>
          <div className="bg-white p-6 rounded-xl border max-h-[500px] overflow-y-auto">
              <h3 className="font-bold mb-4 border-b pb-2">Historial</h3>
              <div className="space-y-4">
                  {history.map(h => (
                      <div key={h.id} className="text-xs border-l-2 pl-3 py-1 relative"><div className="absolute -left-[5px] top-2 w-2 h-2 rounded-full bg-slate-200"></div><p className="font-bold">{h.action} <span className="font-normal text-slate-400">por {h.userName}</span></p><p className="text-[10px] text-slate-400">{new Date(h.timestamp).toLocaleString()}</p>{h.comment && <p className="mt-1 italic">"{h.comment}"</p>}</div>
                  ))}
              </div>
          </div>
      </div>
      {showResponseModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-lg p-6">
                  <h3 className="font-bold text-lg mb-4">{pendingAction === 'APPROVE' ? 'Aprobar' : 'Rechazar'} Solicitud</h3>
                  <div className="bg-blue-50 p-3 rounded mb-4 text-xs flex gap-2"><Info size={16}/> {getCoordinatorRuleHint(doc.state, pendingAction!)}</div>
                  <div className="border-2 border-dashed p-10 text-center rounded relative"><input type="file" onChange={handleResponseFileSelect} className="absolute inset-0 opacity-0 cursor-pointer" />{responseFile ? <p className={isFileValid ? 'text-green-600' : 'text-red-600'}>{responseFile.name}</p> : <p>Seleccionar archivo de respuesta</p>}</div>
                  {fileError.length > 0 && <ul className="text-xs text-red-500 mt-2">{fileError.map((e,i) => <li key={i}>{e}</li>)}</ul>}
                  <div className="flex justify-end gap-2 mt-6"><button onClick={() => setShowResponseModal(false)} className="px-4 py-2">Cancelar</button><button onClick={() => executeTransition(pendingAction, comment, responseFile!, detectedVersion)} disabled={!isFileValid} className="px-6 py-2 bg-indigo-600 text-white rounded-lg disabled:opacity-50">Confirmar</button></div>
              </div>
          </div>
      )}
    </div>
  );
};

export default DocumentDetail;

import React, { useState } from 'react';
import { loginUser, registerUser } from '../services/firebaseAuthService'; 
import { UserService } from '../services/firebaseBackend';
import { MOCK_USERS } from '../constants';
import { User as UserType } from '../types';
import { Lock, User, Key, AlertCircle, TrendingUp, Mail, UserPlus, LogIn } from 'lucide-react'; 
import { useNavigate } from 'react-router-dom'; 
import { auth } from '../services/firebaseConfig'; 
import { GoogleAuthProvider, signInWithPopup } from 'firebase/auth'; 

const Login: React.FC = () => {
    const [isRegistering, setIsRegistering] = useState(false);
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError(''); setLoading(true);
        try {
            if (isRegistering) { await registerUser(email, password, name); navigate('/'); } 
            else { await loginUser(email, password); navigate('/'); }
        } catch (err: any) {
            if (!isRegistering) {
                 let target = MOCK_USERS.find(u => u.email === email && u.password === password);
                 if (!target) { try { const all = await UserService.getAll(); target = all.find(u => u.email === email && u.password === password); } catch(e){} }
                 if (target) { localStorage.setItem('sgd_user_cache', JSON.stringify(target)); window.location.reload(); return; }
            }
            setError(err.message || 'Error de autenticación'); setLoading(false);
        }
    };

    const handleGoogleSignIn = async () => {
        setLoading(true);
        try { await signInWithPopup(auth, new GoogleAuthProvider()); navigate('/'); } 
        catch (err: any) { setError("Error Google"); setLoading(false); }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-slate-100 p-4">
            <div className="bg-white p-8 rounded-xl shadow-lg w-full max-w-md border">
                <div className="text-center mb-6"><h1 className="text-3xl font-bold">SGD</h1><p className="text-slate-500">Gestión Documental</p></div>
                <form onSubmit={handleSubmit} className="space-y-4">
                    {isRegistering && <div className="relative"><User className="absolute left-3 top-2.5 text-slate-400" size={18}/><input placeholder="Nombre" value={name} onChange={(e) => setName(e.target.value)} className="w-full pl-10 pr-3 py-2 border rounded-lg outline-none" required /></div>}
                    <div className="relative"><Mail className="absolute left-3 top-2.5 text-slate-400" size={18}/><input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full pl-10 pr-3 py-2 border rounded-lg outline-none" required /></div>
                    <div className="relative"><Lock className="absolute left-3 top-2.5 text-slate-400" size={18}/><input type="password" placeholder="Contraseña" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full pl-10 pr-3 py-2 border rounded-lg outline-none" required /></div>
                    {error && <p className="text-xs text-red-600 bg-red-50 p-2 rounded border border-red-100">{error}</p>}
                    <button type="submit" disabled={loading} className="w-full bg-indigo-600 text-white py-2.5 rounded-lg font-bold disabled:opacity-70">{loading ? '...' : (isRegistering ? 'Crear Cuenta' : 'Entrar')}</button>
                    <div className="flex justify-center py-2 text-xs"><button type="button" onClick={() => setIsRegistering(!isRegistering)} className="text-indigo-600 hover:underline">{isRegistering ? 'Ya tengo cuenta' : 'Crear nueva cuenta'}</button></div>
                    <button type="button" onClick={handleGoogleSignIn} disabled={loading} className="w-full bg-white border py-2.5 rounded-lg font-bold flex items-center justify-center gap-2 hover:bg-slate-50"><TrendingUp size={18} className="text-red-500"/> Google</button>
                </form>
            </div>
        </div>
    );
};

export default Login;

import React, { useState, useEffect } from 'react';
import { UserService } from '../services/firebaseBackend';
