                <div className="flex justify-end pt-2"><button type="submit" disabled={loading} className="bg-indigo-600 text-white px-6 py-2 rounded-lg font-bold">{loading ? '...' : 'Guardar'}</button></div>
                {msg && <p className="text-xs text-center">{msg === 'OK' ? 'Guardado correctamente' : 'Error al guardar'}</p>}
            </form>
        </div>
