  );
};

export default Profile;

import React, { useEffect, useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService, HistoryService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocState, FullHierarchy, DocType, UserRole, DocHistory } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, AreaChart, Area
} from 'recharts';
import { LayoutDashboard, Filter, Loader2, BarChart2, ShieldAlert, TableProperties, Layers, Clock, Activity, Users, ShieldCheck, CheckCircle } from 'lucide-react';

const STATE_COLOR_MAP: Record<string, string> = { 'No Iniciado': '#94a3b8', 'En Proceso': '#3b82f6', 'Referente': '#a855f7', 'Control': '#f97316', 'Terminados': '#22c55e' };

const Reports: React.FC<{user: User}> = ({ user }) => {
    const navigate = useNavigate();
    const [realDocs, setRealDocs] = useState<Document[]>([]);
    const [history, setHistory] = useState<DocHistory[]>([]);
    const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState<'REPORTS' | 'SUMMARY' | 'CLOSURE'>('REPORTS');
    const [filterProject, setFilterProject] = useState('');
    const [closureMonth, setClosureMonth] = useState('2025-12');

    useEffect(() => { loadData(); }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [d, h, hist] = await Promise.all([DocumentService.getAll(), HierarchyService.getFullHierarchy(), HistoryService.getAll()]);
            setRealDocs(d); setHierarchy(h); setHistory(hist);
        } finally { setLoading(false); }
    };

    const unified = useMemo(() => {
        const list: Document[] = [];
        const realDocMap = new Map();
        realDocs.forEach(d => realDocMap.set(`${normalizeHeader(d.project || '')}|${normalizeHeader(d.microprocess || '')}|${normalizeHeader(d.docType || '')}`, d));
        Object.keys(hierarchy).forEach(proj => {
            Object.keys(hierarchy[proj]).forEach(macro => {
                Object.keys(hierarchy[proj][macro]).forEach(proc => {
                    hierarchy[proj][macro][proc].forEach(node => {
                        if (node.active === false) return;
                        node.requiredTypes?.forEach(type => {
                            const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;
                            if (realDocMap.has(key)) list.push({...realDocMap.get(key), project: proj, microprocess: node.name});
                            else list.push({ id: `v-${key}`, title: node.name, project: proj, microprocess: node.name, docType: type, state: DocState.NOT_STARTED, authorId: '', authorName: '', assignees: node.assignees, version: '', progress: 0, files: [], createdAt: '', updatedAt: '' });
                        });
                    });
                });
            });
        });
        return list;
    }, [realDocs, hierarchy]);

    const filtered = useMemo(() => filterProject ? unified.filter(d => d.project === filterProject) : unified, [unified, filterProject]);

    const stateData = useMemo(() => {
        const counts = { ns: 0, ip: 0, ref: 0, ct: 0, fn: 0 };
        filtered.forEach(d => {
            if (d.state === DocState.NOT_STARTED) counts.ns++;
            else if (d.state === DocState.APPROVED) counts.fn++;
            else if (d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW) counts.ref++;
            else if (d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW) counts.ct++;
            else counts.ip++;
        });
        return [ { name: 'No Iniciado', value: counts.ns }, { name: 'En Proceso', value: counts.ip }, { name: 'Referente', value: counts.ref }, { name: 'Control', value: counts.ct }, { name: 'Terminados', value: counts.fn } ];
    }, [filtered]);

    if (loading) return <div className="p-8 text-center"><Loader2 className="animate-spin mx-auto" /></div>;

    return (
        <div className="space-y-6 pb-12">
            <div className="flex justify-between items-center">
                <h1 className="text-2xl font-bold flex items-center gap-2"><LayoutDashboard className="text-indigo-600" /> Panel de Control</h1>
                <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="p-2 border rounded-lg text-sm outline-none"><option value="">Todos los Proyectos</option>{Object.keys(hierarchy).map(p => <option key={p} value={p}>{p}</option>)}</select>
            </div>
            <div className="flex bg-slate-100 p-1 rounded-xl w-fit gap-1">
                <button onClick={() => setActiveTab('REPORTS')} className={`px-6 py-2.5 rounded-lg text-sm font-bold ${activeTab === 'REPORTS' ? 'bg-white shadow-sm' : 'text-slate-500'}`}>Métricas</button>
