import React, { useEffect, useState, useMemo } from 'react';
import { Link } from 'react-router-dom';
import { DocumentService, HierarchyService } from '../services/firebaseBackend';
import { Document, User, DocState, UserRole, DocType } from '../types';
import { STATE_CONFIG } from '../constants';
import { ListTodo, ArrowRight, FileText, Search } from 'lucide-react';

const WorkList: React.FC<{user: User}> = ({ user }) => {
  const [docs, setDocs] = useState<Document[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');

  useEffect(() => { loadData(); }, []);

  const loadData = async () => {
    setLoading(true);
    try {
        const [real, hierarchy] = await Promise.all([DocumentService.getAll(), HierarchyService.getFullHierarchy()]);
        const work: Document[] = [];
        const isReviewer = user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR;
        const reviewStates = [DocState.INTERNAL_REVIEW, DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW, DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW];

        real.forEach(d => {
            const isAssigned = d.assignees?.includes(user.id);
            const needsReview = isReviewer && reviewStates.includes(d.state);
            if ((isAssigned || needsReview) && d.state !== DocState.APPROVED) work.push(d);
        });

        // Add virtual ones assigned in matrix
        Object.keys(hierarchy).forEach(p => {
            Object.keys(hierarchy[p]).forEach(m => {
                Object.keys(hierarchy[p][m]).forEach(proc => {
                    hierarchy[p][m][proc].forEach(node => {
                        if (node.assignees?.includes(user.id)) {
                            node.requiredTypes?.forEach(type => {
                                const exists = work.some(w => w.project === p && w.microprocess === node.name && w.docType === type);
                                if (!exists) work.push({ id: `v-${p}-${node.name}-${type}`, title: `${node.name} - ${type}`, microprocess: node.name, docType: type, state: DocState.NOT_STARTED, project: p, authorId: '', authorName: '', assignees: node.assignees, version: '-', progress: 0, files: [], createdAt: '', updatedAt: '' });
                            });
                        }
                    });
                });
            });
        });
        setDocs(work);
    } finally { setLoading(false); }
  };

  const filtered = useMemo(() => docs.filter(d => d.title.toLowerCase().includes(search.toLowerCase())), [docs, search]);

  if (loading) return <div className="p-8 text-center">Cargando...</div>;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center"><h1 className="text-2xl font-bold flex items-center gap-2"><ListTodo className="text-indigo-600" /> Tareas</h1><input placeholder="Filtrar..." value={search} onChange={(e) => setSearch(e.target.value)} className="p-2 border rounded-lg text-sm" /></div>
      <div className="bg-white rounded-xl shadow-sm border divide-y">
          {filtered.length === 0 ? <p className="p-8 text-center text-slate-400">Todo al día.</p> : filtered.map(d => (
              <div key={d.id} className="p-4 flex items-center justify-between hover:bg-slate-50">
                  <div className="flex items-center gap-4">
                      <div className={`p-2 rounded-lg ${d.state === DocState.NOT_STARTED ? 'bg-slate-100' : 'bg-indigo-100'}`}><FileText size={20} className="text-indigo-600" /></div>
                      <div><p className="font-bold text-sm">{d.title}</p><p className="text-xs text-slate-500">{d.project} • {STATE_CONFIG[d.state].label.split('(')[0]}</p></div>
                  </div>
                  <Link to={`/doc/${d.id}`} className="text-indigo-600 text-xs font-bold flex items-center gap-1">Ver <ArrowRight size={14}/></Link>
              </div>
          ))}
      </div>
    </div>
  );
};

export default WorkList;

