interface DashboardDoc extends Document {
    isRequired: boolean;
}

const Dashboard: React.FC<{user: User}> = ({ user }) => {
  const navigate = useNavigate();
  const location = useLocation(); 
  const [mergedDocs, setMergedDocs] = useState<DashboardDoc[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [filterProject, setFilterProject] = useState('');
  const [filterSearch, setFilterSearch] = useState(''); 
  const [quickFilter, setQuickFilter] = useState('ALL');
  const [currentPage, setCurrentPage] = useState(1);

  useEffect(() => { loadData(); }, [location.state]);

  const loadData = async () => {
    setLoading(true);
    try {
        const [realDocs, users, fullHierarchy] = await Promise.all([DocumentService.getAll(), UserService.getAll(), HierarchyService.getFullHierarchy()]);
        setAllUsers(users);
        const finalDocs: DashboardDoc[] = [];
        const realDocMap = new Map<string, Document>();
        realDocs.forEach(d => {
            const key = `${normalizeHeader(d.project || '')}|${normalizeHeader(d.microprocess || '')}|${normalizeHeader(d.docType || '')}`;
            realDocMap.set(key, d);
        });

        Object.keys(fullHierarchy).forEach(proj => {
            Object.keys(fullHierarchy[proj]).forEach(macro => {
                Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                    fullHierarchy[proj][macro][proc].forEach(node => {
                        if (node.active === false) return;
                        node.requiredTypes?.forEach(type => {
                            const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;
                            if (realDocMap.has(key)) {
                                finalDocs.push({ ...realDocMap.get(key)!, macroprocess: macro, process: proc, project: proj, isRequired: true });
                            } else {
                                // Fix: Added missing 'description' property
                                finalDocs.push({ id: `virtual-${key}`, title: `${node.name} - ${type}`, description: '', microprocess: node.name, docType: type, state: DocState.NOT_STARTED, project: proj, macroprocess: macro, process: proc, authorId: '', authorName: '', assignees: node.assignees || [], version: '-', progress: 0, files: [], createdAt: '', updatedAt: '', isRequired: true });
                            }
                        });
                    });
                });
            });
        });
        setMergedDocs(finalDocs);
    } finally { setLoading(false); }
  };

  const filtered = useMemo(() => {
      let docs = mergedDocs;
      if (filterProject) docs = docs.filter(d => d.project === filterProject);
      if (filterSearch) docs = docs.filter(d => d.title.toLowerCase().includes(filterSearch.toLowerCase()));
      if (quickFilter !== 'ALL') {
          if (quickFilter === 'FINISHED') docs = docs.filter(d => d.state === DocState.APPROVED);
          else if (quickFilter === 'NOT_STARTED') docs = docs.filter(d => d.state === DocState.NOT_STARTED);
      }
      return docs;
  }, [mergedDocs, filterProject, filterSearch, quickFilter]);

  if (loading) return <div className="p-8 text-center">Cargando tablero...</div>;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex justify-between items-center">
          <h1 className="text-2xl font-bold">Dashboard</h1>
          <div className="flex gap-2">
              <input placeholder="Buscar..." value={filterSearch} onChange={(e) => setFilterSearch(e.target.value)} className="border rounded px-2 text-sm" />
              <Link to="/new" className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-bold">Nueva Solicitud</Link>
          </div>
      </div>
      <div className="bg-white rounded-xl shadow-sm border overflow-x-auto">
          <table className="w-full text-sm text-left">
              <thead className="bg-slate-50 uppercase text-[10px] font-bold"><tr><th className="p-4">Proyecto</th><th className="p-4">Microproceso</th><th className="p-4">Documento</th><th className="p-4">Estado</th><th className="p-4 text-right">Actualizado</th></tr></thead>
              <tbody className="divide-y">
                  {filtered.slice((currentPage - 1) * 10, currentPage * 10).map(doc => (
                      <tr key={doc.id} onClick={() => navigate(`/doc/${doc.id}`)} className="hover:bg-slate-50 cursor-pointer">
                          <td className="p-4 font-bold">{doc.project}</td>
                          <td className="p-4">{doc.microprocess}</td>
                          <td className="p-4"><span className="bg-indigo-50 text-indigo-700 px-2 py-0.5 rounded text-[10px] font-bold">{doc.docType}</span></td>
                          <td className="p-4"><span className={`px-2 py-1 rounded-full text-[10px] font-bold ${STATE_CONFIG[doc.state].color}`}>{STATE_CONFIG[doc.state].label.split('(')[0]}</span></td>
                          <td className="p-4 text-right text-xs text-slate-400">{doc.updatedAt ? new Date(doc.updatedAt).toLocaleDateString() : '-'}</td>
                      </tr>
                  ))}
              </tbody>
          </table>
      </div>
    </div>
  );
};

